@app.route('/backtest/results/<backtest_id>', methods=['GET'])
@app.route('/api/backtest/results/<backtest_id>', methods=['GET'])
def get_backtest_result(backtest_id):
    """Return one completed backtest record by its stable session id."""
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401

    normalized_id = str(backtest_id or '').strip()
    if not normalized_id:
        return jsonify({'success': False, 'message': 'Backtest result not found'}), 404

    with backtest_history_lock:
        record = next(
            (
                item.copy()
                for item in backtest_history
                if str(item.get('backtestId') or item.get('id') or '') == normalized_id
            ),
            None,
        )

    if record is None:
        return jsonify({
            'success': False,
            'message': 'Backtest result not found',
            'backtestId': normalized_id,
        }), 404

    return jsonify({
        'success': True,
        'result': record,
    }), 200


@app.route('/backtest/history', methods=['GET'])

@app.route('/api/backtest/history', methods=['GET'])

def get_backtest_history():
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    """获取回测历史 - 返回真实的backtest历史数据"""

    try:

        print(f"[Backtest History] 收到回测历史请求")

        print(f"[Backtest History] backtest_history id: {id(backtest_history)}")

        print(f"[Backtest History] backtest_history 大小: {len(backtest_history)}")



        # 使用全局的backtest_history数据

        with backtest_history_lock:

            # 返回最新的历史记录（按createdAt倒序）

            sorted_history = sorted(

                backtest_history,

                key=lambda x: x.get("createdAt", ""),

                reverse=True

            )



            print(f"[Backtest History] 返回 {len(sorted_history)} 条真实回测历史记录")



            # 如果没有真实历史数据，返回空数组

            if len(sorted_history) == 0:

                print(f"[Backtest History] 没有真实回测历史数据")

                return jsonify({

                    "success": True,

                    "history": [],

                    "count": 0,

                    "message": "No real backtest history available"

                }), 200



            return jsonify({

                "success": True,

                "history": sorted_history,

                "count": len(sorted_history),

                "message": f"Found {len(sorted_history)} real backtest records"

            }), 200



    except Exception as e:

        print(f"[Backtest History] 异常: {e}")

        return jsonify({

            "success": False,

            "error": str(e),

            "history": [],

            "count": 0,

            "message": "Error loading backtest history"

        }), 500



# ==================== 策略函数 (用于优化) ====================



def run_moving_average_strategy_for_optimization(data, params, initial_capital, symbol):

    """移动平均线交叉策略 - 简化版用于优化"""

    try:

        short_period = params.get('shortMaPeriod', 20)

        long_period = params.get('longMaPeriod', 50)



        trades = []

        equity_curve = []

        position = 0

        cash = initial_capital



        # 计算移动平均线

        prices = [point['close'] for point in data]

        sma_short = []

        sma_long = []



        for i in range(len(prices)):

            if i >= short_period:

                sma_short.append(sum(prices[i-short_period:i]) / short_period)

            else:

                sma_short.append(prices[i])



            if i >= long_period:

                sma_long.append(sum(prices[i-long_period:i]) / long_period)

            else:

                sma_long.append(prices[i])



        # 执行交易策略

        for i, data_point in enumerate(data):

            date = data_point['timestamp']

            price = data_point.get('open') or data_point['close']
            mark_price = data_point['close']



            # 交易信号

            if i >= max(short_period, long_period):

                # 短期均线上穿长期均线 - 买入信号

                if sma_short[i] > sma_long[i] and (i == 0 or sma_short[i-1] <= sma_long[i-1]):

                    if cash > 0 and position == 0:

                        shares_to_buy = cash // price

                        if shares_to_buy > 0:

                            cost = shares_to_buy * price

                            cash -= cost

                            position = shares_to_buy

                            trades.append({

                                'entryDate': date,

                                'entryPrice': price,

                                'quantity': shares_to_buy,

                                'action': 'BUY'

                            })



                # 短期均线下穿长期均线 - 卖出信号

                elif sma_short[i] < sma_long[i] and (i == 0 or sma_short[i-1] >= sma_long[i-1]):

                    if position > 0:

                        value = position * price

                        cash += value

                        # 更新最近一次交易的退出信息

                        for trade in reversed(trades):

                            if trade.get('exitDate') is None and trade.get('action') == 'BUY':

                                trade['exitDate'] = date

                                trade['exitPrice'] = price

                                trade['pnl'] = round((price - trade['entryPrice']) * trade['quantity'], 2)
                                break

                        position = 0



            # 计算当前权益

            equity = cash + (position * mark_price)

            equity_curve.append({

                'date': date,

                'equity': equity,

                'price': mark_price

            })



        return trades, equity_curve



    except Exception as e:

        print(f"[MA Strategy Error] {str(e)}")

        # 返回空结果而不是抛出异常

        return [], []



def run_rsi_strategy_for_optimization(data, params, initial_capital, symbol):

    """RSI策略 - 简化版用于优化"""

    try:

        rsi_period = params.get('rsiPeriod', 14)

        oversold_level = params.get('oversoldLevel', 30)

        overbought_level = params.get('overboughtLevel', 70)



        trades = []

        equity_curve = []

        position = 0

        cash = initial_capital



        # 计算RSI

        prices = [point['close'] for point in data]

        rsi_values = []



        for i in range(len(prices)):

            if i < rsi_period:

                rsi_values.append(50)  # 默认值

                continue



            # 计算价格变化

            gains = []

            losses = []

            for j in range(i - rsi_period, i):

                change = prices[j + 1] - prices[j]

                if change > 0:

                    gains.append(change)

                    losses.append(0)

                else:

                    gains.append(0)

                    losses.append(abs(change))



            avg_gain = sum(gains) / rsi_period

            avg_loss = sum(losses) / rsi_period



            if avg_loss == 0:

                rsi = 100

            else:

                rs = avg_gain / avg_loss

                rsi = 100 - (100 / (1 + rs))



            rsi_values.append(rsi)



        # 执行交易策略

        for i, data_point in enumerate(data):

            date = data_point['timestamp']

            price = data_point.get('open') or data_point['close']
            mark_price = data_point['close']



            # 交易信号

            if i > rsi_period:

                rsi = rsi_values[i - 1]



                # RSI低于超卖线 - 买入信号

                if rsi < oversold_level and position == 0:

                    if cash > 0:

                        shares_to_buy = cash // price

                        if shares_to_buy > 0:

                            cost = shares_to_buy * price

                            cash -= cost

                            position = shares_to_buy

                            trades.append({

                                'entryDate': date,

                                'entryPrice': price,

                                'quantity': shares_to_buy,

                                'action': 'BUY'

                            })



                # RSI高于超买线 - 卖出信号

                elif rsi > overbought_level and position > 0:

                    value = position * price

                    cash += value

                    # 更新最近一次交易的退出信息

                    for trade in reversed(trades):

                        if trade.get('exitDate') is None and trade.get('action') == 'BUY':

                            trade['exitDate'] = date

                            trade['exitPrice'] = price

                            break

                    position = 0



            # 计算当前权益

            equity = cash + (position * mark_price)

            equity_curve.append({

                'date': date,

                'equity': equity,

                'price': mark_price

            })



        return trades, equity_curve



    except Exception as e:

        print(f"[RSI Strategy Error] {str(e)}")

        # 返回空结果而不是抛出异常

        return [], []



def run_macd_strategy_for_optimization(data, params, initial_capital, symbol):
    """MACD策略参数优化专用回测函数"""
    fast_period = params.get('macdFast', params.get('fast', 12))
    slow_period = params.get('macdSlow', params.get('slow', 26))
    signal_period = params.get('macdSignal', params.get('signal', 9))

    trades = []
    equity_curve = []
    position = 0
    cash = initial_capital

    prices = [point['close'] for point in data]

    # 计算MACD
    ema_fast = []
    ema_slow = []
    macd_line = []
    signal_line = []

    for i in range(len(prices)):
        if i == 0:
            ema_fast.append(prices[i])
            ema_slow.append(prices[i])
        else:
            fast_alpha = 2 / (fast_period + 1)
            slow_alpha = 2 / (slow_period + 1)
            ema_fast.append(prices[i] * fast_alpha + ema_fast[i-1] * (1 - fast_alpha))
            ema_slow.append(prices[i] * slow_alpha + ema_slow[i-1] * (1 - slow_alpha))

        macd = ema_fast[i] - ema_slow[i]
        macd_line.append(macd)

        if i == 0:
            signal_line.append(macd)
        elif i < signal_period:
            signal_line.append(macd)
        else:
            signal_alpha = 2 / (signal_period + 1)
            signal_line.append(macd * signal_alpha + signal_line[i-1] * (1 - signal_alpha))

    # 执行交易
    for i, data_point in enumerate(data):
        date = data_point['timestamp']
        price = data_point['close']

        if i >= max(fast_period, slow_period, signal_period):
            hist_val = macd_line[i] - signal_line[i]
            prev_hist = macd_line[i-1] - signal_line[i-1] if i > 0 else 0
            # MACD上穿信号线 -> 买入
            if hist_val > 0 and prev_hist <= 0 and position == 0:
                if cash > 0:
                    shares_to_buy = cash // price
                    if shares_to_buy > 0:
                        cost = shares_to_buy * price
                        cash -= cost
                        position = shares_to_buy
                        trades.append({
                            'entryDate': date, 'exitDate': None,
                            'entryPrice': price, 'exitPrice': None,
                            'pnl': 0, 'returnPct': 0, 'holdingPeriod': 0,
                            'position': 1, 'action': 'BUY',
                            'quantity': shares_to_buy, 'symbol': symbol
                        })
            # MACD下穿信号线 -> 卖出
            elif hist_val < 0 and prev_hist >= 0 and position > 0:
                value = position * price
                cash += value
                for trade in reversed(trades):
                    if trade.get('exitDate') is None and trade.get('action') == 'BUY':
                        entry_price = trade['entryPrice']
                        pnl = (price - entry_price) * trade['quantity']
                        return_pct = ((price - entry_price) / entry_price) * 100 if entry_price > 0 else 0
                        trade['exitDate'] = date
                        trade['exitPrice'] = price
                        trade['pnl'] = round(pnl, 2)
                        trade['returnPct'] = round(return_pct, 2)
                        trade['holdingPeriod'] = i - next((idx for idx, p in enumerate(data) if p['timestamp'] == trade['entryDate']), i)
                        break
                position = 0

        equity = cash + (position * price)
        equity_curve.append({'date': date, 'equity': equity, 'price': price})

    return trades, equity_curve


def run_bollinger_strategy_for_optimization(data, params, initial_capital, symbol):
    """布林带策略参数优化专用回测函数"""
    period = params.get('bollingerPeriod', params.get('period', 20))
    std_dev = params.get('bollingerStdDev', params.get('std_dev', 2))

    trades = []
    equity_curve = []
    position = 0
    cash = initial_capital

    prices = [point['close'] for point in data]
    sma_values = []
    upper_band = []
    lower_band = []

    for i in range(len(prices)):
        if i >= period:
            sma = sum(prices[i-period:i]) / period
            variance = sum((p - sma) ** 2 for p in prices[i-period:i]) / period
            std = variance ** 0.5
            sma_values.append(sma)
            upper_band.append(sma + std_dev * std)
            lower_band.append(sma - std_dev * std)
        else:
            sma_values.append(prices[i])
            upper_band.append(prices[i])
            lower_band.append(prices[i])

    for i, data_point in enumerate(data):
        date = data_point['timestamp']
        price = data_point['close']

        if i >= period:
            # 价格跌破下轨 -> 买入（超卖反弹）
            if price < lower_band[i] and position == 0:
                if cash > 0:
                    shares_to_buy = cash // price
                    if shares_to_buy > 0:
                        cost = shares_to_buy * price
                        cash -= cost
                        position = shares_to_buy
                        trades.append({
                            'entryDate': date, 'exitDate': None,
                            'entryPrice': price, 'exitPrice': None,
                            'pnl': 0, 'returnPct': 0, 'holdingPeriod': 0,
                            'position': 1, 'action': 'BUY',
                            'quantity': shares_to_buy, 'symbol': symbol
                        })
            # 价格突破上轨 -> 卖出（超买回归）
            elif price > upper_band[i] and position > 0:
                value = position * price
                cash += value
                for trade in reversed(trades):
                    if trade.get('exitDate') is None and trade.get('action') == 'BUY':
                        entry_price = trade['entryPrice']
                        pnl = (price - entry_price) * trade['quantity']
                        return_pct = ((price - entry_price) / entry_price) * 100 if entry_price > 0 else 0
                        trade['exitDate'] = date
                        trade['exitPrice'] = price
                        trade['pnl'] = round(pnl, 2)
                        trade['returnPct'] = round(return_pct, 2)
                        trade['holdingPeriod'] = i - next((idx for idx, p in enumerate(data) if p['timestamp'] == trade['entryDate']), i)
                        break
                position = 0

        equity = cash + (position * price)
        equity_curve.append({'date': date, 'equity': equity, 'price': price})

    return trades, equity_curve


def run_momentum_strategy_for_optimization(data, params, initial_capital, symbol):
    """动量策略参数优化专用回测函数（支持阈值）"""
    period = params.get('momentumPeriod', params.get('momentum_period', 10))
    threshold = params.get('momentumThreshold', params.get('momentum_threshold', 0))

    trades = []
    equity_curve = []
    position = 0
    cash = initial_capital

    prices = [point['close'] for point in data]
    momentum_values = []

    for i in range(len(prices)):
        if i >= period:
            momentum = prices[i] - prices[i-period]
            momentum_values.append(momentum)
        else:
            momentum_values.append(0)

    for i, data_point in enumerate(data):
        date = data_point['timestamp']
        price = data_point['close']

        if i >= period:
            # 动量超过正向阈值 -> 买入
            if momentum_values[i] > threshold and position == 0:
                if cash > 0:
                    shares_to_buy = cash // price
                    if shares_to_buy > 0:
                        cost = shares_to_buy * price
                        cash -= cost
                        position = shares_to_buy
                        trades.append({
                            'entryDate': date, 'exitDate': None,
                            'entryPrice': price, 'exitPrice': None,
                            'pnl': 0, 'returnPct': 0, 'holdingPeriod': 0,
                            'position': 1, 'action': 'BUY',
                            'quantity': shares_to_buy, 'symbol': symbol
                        })
            # 动量低于负向阈值 -> 卖出
            elif momentum_values[i] < -threshold and position > 0:
                value = position * price
                cash += value
                for trade in reversed(trades):
                    if trade.get('exitDate') is None and trade.get('action') == 'BUY':
                        entry_price = trade['entryPrice']
                        pnl = (price - entry_price) * trade['quantity']
                        return_pct = ((price - entry_price) / entry_price) * 100 if entry_price > 0 else 0
                        trade['exitDate'] = date
                        trade['exitPrice'] = price
                        trade['pnl'] = round(pnl, 2)
                        trade['returnPct'] = round(return_pct, 2)
                        trade['holdingPeriod'] = i - next((idx for idx, p in enumerate(data) if p['timestamp'] == trade['entryDate']), i)
                        break
                position = 0

        equity = cash + (position * price)
        equity_curve.append({'date': date, 'equity': equity, 'price': price})

    return trades, equity_curve


def run_mean_reversion_strategy_for_optimization(data, params, initial_capital, symbol):
    """Mean Reversion 策略参数优化专用回测函数"""
    lookback = params.get('lookbackPeriod', params.get('lookback', 20))
    entry_z = params.get('entryZScore', params.get('entry_z', -2.0))
    exit_z = params.get('exitZScore', params.get('exit_z', 0.0))
    stop_loss_pct = params.get('stopLossPct', 0.06)
    take_profit_pct = params.get('takeProfitPct', 0.08)
    rsi_period = params.get('rsiPeriod', 14)
    oversold_level = params.get('oversoldLevel', 30)
    enable_trend = params.get('enableTrendFilter', True)
    trend_ma = params.get('trendMaPeriod', 100)

    trades = []
    equity_curve = []
    position = 0
    cash = initial_capital
    entry_price = 0

    prices = [point['close'] for point in data]

    # Pre-compute RSI
    rsi_values = [None] * len(prices)
    if len(prices) > rsi_period:
        gains = []
        losses = []
        for i in range(1, len(prices)):
            ch = prices[i] - prices[i-1]
            gains.append(ch if ch > 0 else 0)
            losses.append(abs(ch) if ch < 0 else 0)
        for i in range(rsi_period, len(gains)):
            avg_gain = sum(gains[i-rsi_period:i]) / rsi_period
            avg_loss = sum(losses[i-rsi_period:i]) / rsi_period
            if avg_loss == 0:
                rsi_values[i+1] = 100
            else:
                rs = avg_gain / avg_loss
                rsi_values[i+1] = 100 - (100 / (1 + rs))

    for i, data_point in enumerate(data):
        date = data_point['timestamp']
        price = data_point['close']

        if i >= lookback:
            window = prices[i-lookback:i]
            mean = sum(window) / lookback
            variance = sum((p - mean) ** 2 for p in window) / lookback
            std = variance ** 0.5
            z_score = (price - mean) / std if std > 0 else 0

            trend_ok = True
            if enable_trend and i >= trend_ma:
                trend_mean = sum(prices[i-trend_ma:i]) / trend_ma
                trend_ok = price > trend_mean * 0.92

            rsi_val = rsi_values[i]
            rsi_ok = rsi_val is not None and rsi_val < oversold_level

            if position == 0 and z_score <= entry_z and (not enable_trend or trend_ok) and rsi_ok:
                if cash > 0:
                    shares = cash // price
                    if shares > 0:
                        cost = shares * price
                        cash -= cost
                        position = shares
                        entry_price = price
                        trades.append({
                            'entryDate': date, 'exitDate': None,
                            'entryPrice': price, 'exitPrice': None,
                            'pnl': 0, 'returnPct': 0, 'holdingPeriod': 0,
                            'position': 1, 'action': 'BUY',
                            'quantity': shares, 'symbol': symbol
                        })
            elif position > 0:
                sell = False
                if z_score >= exit_z:
                    sell = True
                elif entry_price > 0 and price <= entry_price * (1 - stop_loss_pct):
                    sell = True
                elif entry_price > 0 and price >= entry_price * (1 + take_profit_pct):
                    sell = True
                if sell:
                    value = position * price
                    cash += value
                    for trade in reversed(trades):
                        if trade.get('exitDate') is None and trade.get('action') == 'BUY':
                            pnl = (price - trade['entryPrice']) * trade['quantity']
                            ret = ((price - trade['entryPrice']) / trade['entryPrice']) * 100 if trade['entryPrice'] > 0 else 0
                            trade['exitDate'] = date
                            trade['exitPrice'] = price
                            trade['pnl'] = round(pnl, 2)
                            trade['returnPct'] = round(ret, 2)
                            trade['holdingPeriod'] = i - next((idx for idx, p in enumerate(data) if p['timestamp'] == trade['entryDate']), i)
                            break
                    position = 0
                    entry_price = 0

        equity = cash + (position * price)
        equity_curve.append({'date': date, 'equity': equity, 'price': price})

    return trades, equity_curve


def _bt_sma(values, period):
    out = []
    for i, value in enumerate(values):
        if i + 1 >= period:
            window = values[i - period + 1:i + 1]
            out.append(sum(window) / period)
        else:
            out.append(value)
    return out


def _bt_ema(values, period):
    out = []
    alpha = 2 / (period + 1)
    for i, value in enumerate(values):
        if i == 0:
            out.append(value)
        else:
            out.append(value * alpha + out[-1] * (1 - alpha))
    return out


def _bt_true_ranges(data):
    tr = []
    for i, bar in enumerate(data):
        high = float(bar.get('high', bar.get('close', 0)) or 0)
        low = float(bar.get('low', bar.get('close', 0)) or 0)
        close = float(bar.get('close', 0) or 0)
        prev_close = float(data[i - 1].get('close', close) or close) if i > 0 else close
        tr.append(max(high - low, abs(high - prev_close), abs(low - prev_close)))
    return tr


def _bt_atr(data, period=14):
    tr = _bt_true_ranges(data)
    atr = []
    for i, value in enumerate(tr):
        if i == 0:
            atr.append(value)
        elif i < period:
            atr.append(sum(tr[:i + 1]) / (i + 1))
        else:
            atr.append((atr[-1] * (period - 1) + value) / period)
    return atr


def _bt_open_long(trades, cash, price, date, symbol):
    if price <= 0 or cash <= 0:
        return cash, 0
    shares = cash // price
    if shares <= 0:
        return cash, 0
    cash -= shares * price
    trades.append({
        'entryDate': date, 'exitDate': None,
        'entryPrice': price, 'exitPrice': None,
        'pnl': 0, 'returnPct': 0, 'holdingPeriod': 0,
        'position': 1, 'action': 'BUY',
        'quantity': shares, 'symbol': symbol
    })
    return cash, shares


def _bt_close_long(trades, cash, position, price, date, data, current_index):
    if position <= 0:
        return cash
    cash += position * price
    for trade in reversed(trades):
        if trade.get('exitDate') is None and trade.get('action') == 'BUY':
            entry_price = trade.get('entryPrice', 0) or 0
            qty = trade.get('quantity', position) or position
            pnl = (price - entry_price) * qty
            ret = ((price - entry_price) / entry_price) * 100 if entry_price > 0 else 0
            trade['exitDate'] = date
            trade['exitPrice'] = price
            trade['pnl'] = round(pnl, 2)
            trade['returnPct'] = round(ret, 2)
            trade['holdingPeriod'] = current_index - next((idx for idx, p in enumerate(data) if p.get('timestamp') == trade.get('entryDate')), current_index)
            break
    return cash


def _bt_adx(data, period=14):
    highs = [float(point.get('high', point.get('close', 0)) or 0) for point in data]
    lows = [float(point.get('low', point.get('close', 0)) or 0) for point in data]
    closes = [float(point.get('close', 0) or 0) for point in data]
    tr = _bt_true_ranges(data)
    plus_dm = [0]
    minus_dm = [0]
    for i in range(1, len(data)):
        up_move = highs[i] - highs[i - 1]
        down_move = lows[i - 1] - lows[i]
        plus_dm.append(up_move if up_move > down_move and up_move > 0 else 0)
        minus_dm.append(down_move if down_move > up_move and down_move > 0 else 0)

    sm_tr, sm_plus, sm_minus = [], [], []
    for i in range(len(data)):
        if i == 0:
            sm_tr.append(tr[i])
            sm_plus.append(plus_dm[i])
            sm_minus.append(minus_dm[i])
        elif i < period:
            sm_tr.append(sum(tr[:i + 1]))
            sm_plus.append(sum(plus_dm[:i + 1]))
            sm_minus.append(sum(minus_dm[:i + 1]))
        else:
            sm_tr.append(sm_tr[-1] - (sm_tr[-1] / period) + tr[i])
            sm_plus.append(sm_plus[-1] - (sm_plus[-1] / period) + plus_dm[i])
            sm_minus.append(sm_minus[-1] - (sm_minus[-1] / period) + minus_dm[i])

    plus_di, minus_di, dx = [], [], []
    for i in range(len(data)):
        if sm_tr[i] <= 0:
            plus_di.append(0)
            minus_di.append(0)
            dx.append(0)
            continue
        pdi = 100 * sm_plus[i] / sm_tr[i]
        mdi = 100 * sm_minus[i] / sm_tr[i]
        plus_di.append(pdi)
        minus_di.append(mdi)
        denom = pdi + mdi
        dx.append(100 * abs(pdi - mdi) / denom if denom > 0 else 0)

    adx = []
    for i, value in enumerate(dx):
        if i < period:
            adx.append(sum(dx[:i + 1]) / (i + 1))
        else:
            adx.append((adx[-1] * (period - 1) + value) / period)
    return adx, plus_di, minus_di


def run_buy_hold_strategy_for_optimization(data, params, initial_capital, symbol):
    """Buy-and-hold benchmark."""
    trades = []
    equity_curve = []
    if not data:
        return trades, equity_curve
    cash = initial_capital
    position = 0
    for i, point in enumerate(data):
        date = point['timestamp']
        price = point['close']
        if i == 0 and position == 0:
            cash, position = _bt_open_long(trades, cash, price, date, symbol)
        equity_curve.append({'date': date, 'equity': cash + position * price, 'price': price})
    return trades, equity_curve


def run_donchian_breakout_strategy_for_optimization(data, params, initial_capital, symbol):
    """Donchian/Turtle-style channel breakout, using prior-window highs/lows."""
    entry_period = int(params.get('entryPeriod', params.get('donchianEntryPeriod', 20)))
    exit_period = int(params.get('exitPeriod', params.get('donchianExitPeriod', 10)))
    atr_period = int(params.get('atrPeriod', 20))
    atr_stop = float(params.get('atrStopMultiple', 2.0))
    trades, equity_curve = [], []
    position, cash, entry_price, highest_since_entry = 0, initial_capital, 0, 0
    atr = _bt_atr(data, atr_period)

    for i, point in enumerate(data):
        date, price = point['timestamp'], point['close']
        if i >= max(entry_period, exit_period, atr_period):
            prior_high = max(p.get('high', p.get('close', 0)) for p in data[i - entry_period:i])
            prior_low = min(p.get('low', p.get('close', 0)) for p in data[i - exit_period:i])
            if position == 0 and price > prior_high:
                cash, position = _bt_open_long(trades, cash, price, date, symbol)
                entry_price = price
                highest_since_entry = price
            elif position > 0:
                highest_since_entry = max(highest_since_entry, point.get('high', price))
                trailing_stop = highest_since_entry - atr_stop * atr[i]
                if price < prior_low or price <= trailing_stop:
                    cash = _bt_close_long(trades, cash, position, price, date, data, i)
                    position, entry_price, highest_since_entry = 0, 0, 0
        equity_curve.append({'date': date, 'equity': cash + position * price, 'price': price})
    return trades, equity_curve


def run_keltner_breakout_strategy_for_optimization(data, params, initial_capital, symbol):
    """Keltner Channel breakout with EMA basis and ATR bands."""
    ema_period = int(params.get('emaPeriod', params.get('keltnerEmaPeriod', 20)))
    atr_period = int(params.get('atrPeriod', params.get('keltnerAtrPeriod', 20)))
    mult = float(params.get('atrMultiplier', params.get('keltnerMultiplier', 2.0)))
    trades, equity_curve = [], []
    position, cash = 0, initial_capital
    closes = [point['close'] for point in data]
    ema = _bt_ema(closes, ema_period)
    atr = _bt_atr(data, atr_period)
    warmup = max(ema_period, atr_period)

    for i, point in enumerate(data):
        date, price = point['timestamp'], point['close']
        if i >= warmup:
            upper_prev = ema[i - 1] + mult * atr[i - 1]
            mid_prev = ema[i - 1]
            lower_prev = ema[i - 1] - mult * atr[i - 1]
            if position == 0 and price > upper_prev:
                cash, position = _bt_open_long(trades, cash, price, date, symbol)
            elif position > 0 and (price < mid_prev or price < lower_prev):
                cash = _bt_close_long(trades, cash, position, price, date, data, i)
                position = 0
        equity_curve.append({'date': date, 'equity': cash + position * price, 'price': price})
    return trades, equity_curve


def run_supertrend_strategy_for_optimization(data, params, initial_capital, symbol):
    """SuperTrend trend-following strategy based on ATR bands."""
    atr_period = int(params.get('atrPeriod', params.get('supertrendAtrPeriod', 10)))
    mult = float(params.get('multiplier', params.get('supertrendMultiplier', 3.0)))
    trades, equity_curve = [], []
    position, cash = 0, initial_capital
    atr = _bt_atr(data, atr_period)
    final_upper, final_lower, trend_up = [], [], []

    for i, point in enumerate(data):
        high = point.get('high', point.get('close', 0))
        low = point.get('low', point.get('close', 0))
        close = point.get('close', 0)
        hl2 = (high + low) / 2
        basic_upper = hl2 + mult * atr[i]
        basic_lower = hl2 - mult * atr[i]
        if i == 0:
            final_upper.append(basic_upper)
            final_lower.append(basic_lower)
            trend_up.append(True)
            equity_curve.append({'date': point['timestamp'], 'equity': cash, 'price': close})
            continue
        prev_close = data[i - 1].get('close', close)
        upper = basic_upper if basic_upper < final_upper[-1] or prev_close > final_upper[-1] else final_upper[-1]
        lower = basic_lower if basic_lower > final_lower[-1] or prev_close < final_lower[-1] else final_lower[-1]
        if close > final_upper[-1]:
            is_up = True
        elif close < final_lower[-1]:
            is_up = False
        else:
            is_up = trend_up[-1]
        final_upper.append(upper)
        final_lower.append(lower)
        trend_up.append(is_up)

        date = point['timestamp']
        if i >= atr_period:
            if position == 0 and is_up and not trend_up[i - 1]:
                cash, position = _bt_open_long(trades, cash, close, date, symbol)
            elif position > 0 and (not is_up and trend_up[i - 1]):
                cash = _bt_close_long(trades, cash, position, close, date, data, i)
                position = 0
        equity_curve.append({'date': date, 'equity': cash + position * close, 'price': close})
    return trades, equity_curve


def run_stochastic_strategy_for_optimization(data, params, initial_capital, symbol):
    """Stochastic oscillator reversal strategy."""
    k_period = int(params.get('kPeriod', params.get('stochKPeriod', 14)))
    d_period = int(params.get('dPeriod', params.get('stochDPeriod', 3)))
    oversold = float(params.get('oversold', params.get('stochOversold', 20)))
    overbought = float(params.get('overbought', params.get('stochOverbought', 80)))
    trades, equity_curve = [], []
    position, cash = 0, initial_capital
    k_values, d_values = [], []

    for i, point in enumerate(data):
        price = point['close']
        if i + 1 >= k_period:
            window = data[i - k_period + 1:i + 1]
            high_n = max(p.get('high', p.get('close', 0)) for p in window)
            low_n = min(p.get('low', p.get('close', 0)) for p in window)
            k = 100 * (price - low_n) / (high_n - low_n) if high_n > low_n else 50
        else:
            k = 50
        k_values.append(k)
        if len(k_values) >= d_period:
            d_values.append(sum(k_values[-d_period:]) / d_period)
        else:
            d_values.append(k)

        if i >= k_period + d_period:
            prev_k, prev_d = k_values[i - 1], d_values[i - 1]
            cur_k, cur_d = k_values[i], d_values[i]
            date = point['timestamp']
            if position == 0 and prev_k <= prev_d and cur_k > cur_d and cur_k <= oversold + 10:
                cash, position = _bt_open_long(trades, cash, price, date, symbol)
            elif position > 0 and prev_k >= prev_d and cur_k < cur_d and cur_k >= overbought - 10:
                cash = _bt_close_long(trades, cash, position, price, date, data, i)
                position = 0
        equity_curve.append({'date': point['timestamp'], 'equity': cash + position * price, 'price': price})
    return trades, equity_curve


def run_adx_trend_strategy_for_optimization(data, params, initial_capital, symbol):
    """ADX + EMA trend filter strategy."""
    adx_period = int(params.get('adxPeriod', 14))
    threshold = float(params.get('adxThreshold', 25))
    fast_period = int(params.get('fastEmaPeriod', 20))
    slow_period = int(params.get('slowEmaPeriod', 50))
    trades, equity_curve = [], []
    position, cash = 0, initial_capital
    closes = [point['close'] for point in data]
    fast = _bt_ema(closes, fast_period)
    slow = _bt_ema(closes, slow_period)
    adx, plus_di, minus_di = _bt_adx(data, adx_period)
    warmup = max(adx_period * 2, slow_period)

    for i, point in enumerate(data):
        date, price = point['timestamp'], point['close']
        if i >= warmup:
            trend_long = adx[i] >= threshold and plus_di[i] > minus_di[i] and fast[i] > slow[i]
            trend_exit = minus_di[i] > plus_di[i] or fast[i] < slow[i] or adx[i] < threshold * 0.75
            if position == 0 and trend_long:
                cash, position = _bt_open_long(trades, cash, price, date, symbol)
            elif position > 0 and trend_exit:
                cash = _bt_close_long(trades, cash, position, price, date, data, i)
                position = 0
        equity_curve.append({'date': date, 'equity': cash + position * price, 'price': price})
    return trades, equity_curve


