# ============ AI Final Candidate Selection ============

@app.route('/api/ai/fine-scan-select', methods=['POST'])
def fine_scan_select():
    """
    AI final selection of top 3-5 stocks for next step.
    Called once after all symbols have completed Fine Scan.
    Receives all candidate results, returns AI-ranked picks.
    """
    import json as _json
    import time as _time

    start_ts = _time.time()
    try:
        data = request.get_json(force=True, silent=True) or {}
        candidates = data.get('candidates', [])
        if not candidates:
            return jsonify({'success': False, 'message': 'No candidates provided'}), 400

        # Build structured input for AI
        candidate_lines = []
        for c in candidates:
            sym = c.get('symbol', '?')
            bt_stat = c.get('backtestStatus', 'N/A')
            bt_perf = c.get('backtestPerformance', 'N/A')
            bt_return = c.get('backtestReturn', '')
            opt_stab = c.get('optimizationStability', '')
            entry = c.get('entryQuality', 'N/A')
            entry_rr = c.get('entryRR', '')
            liq = c.get('liquidityGrade', 'N/A')
            news = c.get('newsGrade', 'N/A')
            risk = c.get('riskGrade', 'N/A')
            regime = c.get('marketRegime', '')
            strategy = c.get('matchedStrategy', '')
            score = c.get('matchConfidence', 0)
            candidate_lines.append(
                f"- {sym}: BT={bt_stat} perf={bt_perf}"
                f"{'(' + str(bt_return) + ')' if bt_return else ''}"
                f" opt={opt_stab} entry={entry}"
                f"{' R/R=' + str(entry_rr) if entry_rr else ''}"
                f" liq={liq} news={news} risk={risk}"
                f" regime={regime} strat={strategy} score={score}"
            )

        ai_prompt = f"""You are a quantitative trading analyst. Select the best 3-5 stocks for the NEXT TRADE based on all scan results.

Rules:
1. Select ONLY candidates with actionable combination of strengths and acceptable risks
2. Prefer: strong backtest + stable optimization + Good/Excellent entry + acceptable liquidity + controllable risk
3. Do NOT select: SKIP risk, Data Unavailable on key fields, very poor liquidity, or very poor reward/risk
4. EXCEPTION: you may select borderline stocks ONLY if you explain why (e.g. "strong backtest despite poor entry")

Return EXACTLY this JSON format (no markdown, no extra text):
{{
  "selected": [
    {{
      "rank": 1,
      "symbol": "AAPL",
      "decision": "Continue|Watch|Skip",
      "confidence": 85,
      "main_reason": "strong backtest with stable params, good entry near support, acceptable liquidity",
      "risk": "MEDIUM",
      "next_step": "Monitor for pullback to EMA20 before entry on Monday"
    }}
  ],
  "explanation": "Brief overall reasoning for the selection"
}}

Candidates:
{chr(10).join(candidate_lines)}

Return ONLY the JSON. No preamble."""
        # Read AI config
        _resolved_ai, _ai_src = resolve_ai_config(require_user_config=True)
        api_key = _resolved_ai.get('apiKey', '')
        if not api_key or len(api_key) < 10:
            return jsonify({
                'success': False,
                'message': 'AI config: no valid API key. Cannot generate AI-selected list.',
                'ai_skipped': True,
                'fallback': False,
                'selected': []
            })

        provider = _resolved_ai.get('provider', 'deepseek')
        base_url = _resolved_ai.get('baseURL', 'https://api.deepseek.com')
        model = _resolved_ai.get('model', 'deepseek-chat')

        ai_headers = {
            'Authorization': f'Bearer {api_key}',
            'Content-Type': 'application/json'
        }

        ai_payload = {
            'model': model,
            'messages': [
                {'role': 'system', 'content': 'You are a quantitative trading analyst. Return only valid JSON.'},
                {'role': 'user', 'content': ai_prompt}
            ],
            'max_tokens': 2000,
            'temperature': 0.3,
        }

        if not base_url.startswith('http'):
            base_url = 'https://' + base_url

        resp = ai_chat_request(f'{base_url}/chat/completions', headers=ai_headers, json_data=ai_payload, timeout=30, provider=_resolved_ai.get('provider'))

        if resp.status_code != 200:
            print(f'[FINE SCAN SELECT] AI HTTP {resp.status_code}: {resp.text[:200]}')
            return jsonify({
                'success': False,
                'message': f'AI returned HTTP {resp.status_code}. Cannot generate AI-selected list.',
                'ai_skipped': True,
                'fallback': False,
                'selected': []
            })

        ai_content = resp.json().get('choices', [{}])[0].get('message', {}).get('content', '')
        # Strip markdown fences if present
        ai_content = ai_content.strip()
        if ai_content.startswith('```'):
            ai_content = ai_content.split('\\n', 1)[-1] if '\\n' in ai_content else ai_content[3:]
            if ai_content.endswith('```'):
                ai_content = ai_content[:-3]
            ai_content = ai_content.strip()

        try:
            result = _json.loads(ai_content)
        except _json.JSONDecodeError as e:
            print(f'[FINE SCAN SELECT] JSON parse error: {e}, raw: {ai_content[:200]}')
            return jsonify({
                'success': False,
                'message': f'AI returned unparseable JSON: {str(e)}. Cannot generate AI-selected list.',
                'ai_skipped': True,
                'fallback': False,
                'selected': []
            })

        elapsed = round(_time.time() - start_ts, 2)
        print(f'=== FINE SCAN SELECTED: {len(result.get("selected", []))} candidates ({elapsed}s) ===')

        return jsonify({
            'success': True,
            'selected': result.get('selected', []),
            'explanation': result.get('explanation', ''),
            'ai_skipped': False,
            'elapsed': elapsed
        })

    except Exception as e:
        print(f'[FINE SCAN SELECT ERROR] {e}')
        import traceback as _tb
        _tb.print_exc()
        return jsonify({
            'success': False,
            'message': f'AI selection failed: {str(e)}. Cannot generate AI-selected list.',
            'ai_skipped': True,
            'fallback': False,
            'selected': []
        })


def _rank_fallback(candidates):
    """Deterministic fallback ranking when AI is unavailable."""
    scored = []
    for c in candidates:
        score = 0
        bt = c.get('backtestPerformance', '')
        if bt == 'positive': score += 30
        elif bt == 'caution': score += 10
        opt = c.get('optimizationStability', '')
        if opt == 'Stable': score += 20
        elif opt == 'Weak': score += 5
        entry = c.get('entryQuality', '')
        if entry in ('Excellent', 'Good'): score += 25
        elif entry == 'Wait for Pullback': score += 10
        liq = c.get('liquidityGrade', '')
        if liq == 'Good': score += 15
        elif liq in ('Caution',): score += 5
        risk = c.get('riskGrade', '')
        if risk == 'LOW': score += 20
        elif risk == 'MEDIUM': score += 5
        if risk in ('SKIP',): score = -999
        if liq in ('Poor', 'Data Unavailable'): score -= 10
        if entry in ('Data Unavailable', 'Error / No Data'): score -= 20
        if bt == 'error': score -= 30
        scored.append({'symbol': c.get('symbol', '?'), 'score': score, 'candidate': c})

    scored.sort(key=lambda x: -x['score'])
    selected = []
    rank = 0
    for s in scored:
        if s['score'] <= 0:
            continue
        rank += 1
        if rank > 5:
            break
        c = s['candidate']
        decision = 'Continue' if s['score'] >= 50 else ('Watch' if s['score'] >= 25 else 'Skip')
        selected.append({
            'rank': rank,
            'symbol': s['symbol'],
            'decision': decision,
            'confidence': min(s['score'], 100),
            'main_reason': f'Score={s["score"]}: BT={c.get("backtestPerformance","")} Entry={c.get("entryQuality","")} Risk={c.get("riskGrade","")}',
            'risk': c.get('riskGrade', 'MEDIUM'),
            'next_step': 'Consider entry on pullback' if decision == 'Continue' else 'Monitor for improvement'
        })
    return selected


# ============ Entry Plan Execution Endpoint ============

_watchlist_store = []  # in-memory watchlist (survives until restart)
import uuid as _uuid


def _entry_price_tick(price):
    """Return Alpaca's supported equity order-price increment."""
    try:
        return 0.01 if float(price) >= 1 else 0.0001
    except (TypeError, ValueError):
        return 0.01


def _entry_round_price(price, direction='nearest'):
    """Round an order price without accidentally crossing its protection cap."""
    from decimal import Decimal, ROUND_CEILING, ROUND_FLOOR, ROUND_HALF_UP

    value = Decimal(str(price or 0))
    tick = Decimal(str(_entry_price_tick(value)))
    rounding = {
        'up': ROUND_CEILING,
        'down': ROUND_FLOOR,
    }.get(direction, ROUND_HALF_UP)
    return float((value / tick).to_integral_value(rounding=rounding) * tick)


def _entry_quote_age_seconds(timestamp_value, now=None):
    if not timestamp_value:
        return None
    try:
        parsed = dateutil.parser.isoparse(str(timestamp_value))
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=timezone.utc)
        current = now or datetime.now(timezone.utc)
        return max(0.0, (current - parsed.astimezone(timezone.utc)).total_seconds())
    except Exception:
        return None


def _entry_setup_kind(setup, strategy=None):
    """Normalize an Entry Plan setup into a deterministic trigger family."""
    setup_text = str(setup or '').strip().lower()
    strategy_text = str(strategy or '').strip().lower()
    combined = f'{setup_text} {strategy_text}'
    if any(token in setup_text for token in ('watch', 'no trade', 'avoid', 'event only')):
        return 'ineligible'
    if 'breakout' in setup_text:
        return 'breakout'
    if 'pullback' in setup_text:
        return 'pullback'
    if any(token in setup_text for token in ('support', 'range')):
        if any(token in combined for token in ('mean', 'reversion', 'bollinger', 'rsi')):
            return 'mean_reversion'
        return 'support'
    if any(token in setup_text for token in ('mean', 'reversion', 'bollinger')):
        return 'mean_reversion'
    if any(token in setup_text for token in ('continuation', 'trend', 'momentum', 'moving average', 'macd')):
        return 'continuation'
    return 'ineligible'


def _evaluate_entry_setup_trigger(
    setup,
    executable_price,
    zone_low,
    zone_high,
    *,
    strategy=None,
    latest_bar=None,
    previous_bar=None,
    bar_age_seconds=None,
    resistance=None,
    support=None,
    ema20=None,
    ema50=None,
    rsi14=None,
    macd_histogram=None,
    intraday_volume_ratio=None,
    comparable_volume_ratio=None,
):
    """Evaluate setup-specific entry confirmation without allowing AI overrides.

    The zone is necessary but never sufficient. A completed, recent intraday bar
    and the setup's own confirmation evidence must also pass before auto entry.
    Optional context checks are displayed but do not make the trigger brittle.
    """
    def number(value):
        try:
            if value in (None, ''):
                return None
            parsed = float(value)
            return parsed if parsed == parsed else None
        except (TypeError, ValueError):
            return None

    def bar_value(bar, *keys):
        if not isinstance(bar, dict):
            return None
        for key in keys:
            value = number(bar.get(key))
            if value is not None:
                return value
        return None

    checks = []

    def add_check(name, value, requirement, *, required=True, observed=None):
        available = value is not None
        checks.append({
            'name': name,
            'passed': bool(value) if available else None,
            'available': available,
            'required': required,
            'observed': observed,
            'requirement': requirement,
        })

    setup_kind = _entry_setup_kind(setup, strategy)
    price = number(executable_price)
    low = number(zone_low)
    high = number(zone_high)
    zone_available = price is not None and low is not None and high is not None and low > 0 and high >= low
    in_zone = (low <= price <= high) if zone_available else None
    add_check(
        'Executable price in zone',
        in_zone,
        'ask must be inside the approved entry zone',
        observed=(f'${price:.4f}' if price is not None else None),
    )

    if setup_kind == 'ineligible':
        return {
            'eligible': False,
            'met': False,
            'status': 'NOT_ELIGIBLE',
            'setupKind': setup_kind,
            'checks': checks,
            'missing': [],
            'reasons': ['Setup is research/watch-only and is not eligible for automatic entry.'],
        }

    latest_close = bar_value(latest_bar, 'c', 'close')
    latest_open = bar_value(latest_bar, 'o', 'open')
    latest_low = bar_value(latest_bar, 'l', 'low')
    previous_close = bar_value(previous_bar, 'c', 'close')
    bar_age = number(bar_age_seconds)
    bar_fresh = (bar_age <= 15 * 60) if bar_age is not None else None
    add_check(
        'Completed 5m bar fresh',
        bar_fresh,
        'latest completed 5m bar must be no more than 15 minutes old',
        observed=(f'{bar_age:.0f}s' if bar_age is not None else None),
    )

    volume_ratio = number(intraday_volume_ratio)
    if volume_ratio is None:
        volume_ratio = number(comparable_volume_ratio)
    rsi = number(rsi14)
    ema20_value = number(ema20)
    ema50_value = number(ema50)
    resistance_value = number(resistance)
    support_value = number(support)
    macd_value = number(macd_histogram)

    bullish_reversal = None
    if latest_close is not None and latest_open is not None and previous_close is not None:
        bullish_reversal = latest_close > latest_open and latest_close >= previous_close

    if setup_kind == 'breakout':
        breakout_level = resistance_value if resistance_value and resistance_value > 0 else low
        close_breakout = (
            latest_close > breakout_level
            if latest_close is not None and breakout_level is not None else None
        )
        add_check(
            'Breakout close confirmed',
            close_breakout,
            'completed 5m close must finish above resistance',
            observed=(f'${latest_close:.4f}' if latest_close is not None else None),
        )
        add_check(
            'Breakout participation',
            volume_ratio >= 1.25 if volume_ratio is not None else None,
            'relative volume must be at least 1.25x',
            observed=(f'{volume_ratio:.2f}x' if volume_ratio is not None else None),
        )
        add_check(
            'Trend context',
            latest_close >= ema20_value if latest_close is not None and ema20_value is not None else None,
            'close at or above EMA20',
            required=False,
            observed=(f'EMA20 ${ema20_value:.4f}' if ema20_value is not None else None),
        )
    elif setup_kind == 'pullback':
        add_check(
            'Bullish pullback reversal',
            bullish_reversal,
            'completed 5m bar closes bullish and no lower than the prior close',
            observed=(f'close ${latest_close:.4f}' if latest_close is not None else None),
        )
        trend_aligned = None
        if ema20_value is not None and ema50_value is not None and price is not None:
            trend_aligned = ema20_value > ema50_value and price >= ema50_value
        add_check(
            'Trend structure intact',
            trend_aligned,
            'EMA20 above EMA50 and executable price not below EMA50',
            observed=(
                f'EMA20 ${ema20_value:.4f} / EMA50 ${ema50_value:.4f}'
                if ema20_value is not None and ema50_value is not None else None
            ),
        )
        add_check(
            'RSI reset',
            35 <= rsi <= 65 if rsi is not None else None,
            'RSI14 between 35 and 65',
            observed=(f'{rsi:.1f}' if rsi is not None else None),
        )
        add_check(
            'Orderly volume',
            volume_ratio <= 1.50 if volume_ratio is not None else None,
            'pullback volume no more than 1.50x baseline',
            required=False,
            observed=(f'{volume_ratio:.2f}x' if volume_ratio is not None else None),
        )
    elif setup_kind == 'support':
        add_check(
            'Bullish support reversal',
            bullish_reversal,
            'completed 5m bar closes bullish and no lower than the prior close',
            observed=(f'close ${latest_close:.4f}' if latest_close is not None else None),
        )
        touched_zone = None
        if latest_low is not None and high is not None and latest_close is not None and low is not None:
            touched_zone = latest_low <= high and latest_close >= low
        add_check(
            'Support held',
            touched_zone,
            'bar trades into the zone and closes back above its lower bound',
            observed=(f'low ${latest_low:.4f}' if latest_low is not None else None),
        )
        add_check(
            'Support context',
            latest_close >= support_value if latest_close is not None and support_value is not None else None,
            'close at or above structural support',
            required=False,
            observed=(f'support ${support_value:.4f}' if support_value is not None else None),
        )
    elif setup_kind == 'mean_reversion':
        add_check(
            'Bullish mean-reversion turn',
            bullish_reversal,
            'completed 5m bar closes bullish and no lower than the prior close',
            observed=(f'close ${latest_close:.4f}' if latest_close is not None else None),
        )
        add_check(
            'Oversold evidence',
            rsi <= 42 if rsi is not None else None,
            'RSI14 at or below 42',
            observed=(f'{rsi:.1f}' if rsi is not None else None),
        )
        add_check(
            'Range reclaimed',
            latest_close >= low if latest_close is not None and low is not None else None,
            'completed close back above the lower entry-zone boundary',
            observed=(f'${latest_close:.4f}' if latest_close is not None else None),
        )
    else:  # continuation
        add_check(
            'Price continuation',
            latest_close > previous_close if latest_close is not None and previous_close is not None else None,
            'completed 5m close above the prior completed close',
            observed=(f'${latest_close:.4f}' if latest_close is not None else None),
        )
        trend_aligned = None
        if latest_close is not None and ema20_value is not None and ema50_value is not None:
            trend_aligned = latest_close >= ema20_value and ema20_value > ema50_value
        add_check(
            'Trend alignment',
            trend_aligned,
            'close at or above EMA20 with EMA20 above EMA50',
            observed=(
                f'EMA20 ${ema20_value:.4f} / EMA50 ${ema50_value:.4f}'
                if ema20_value is not None and ema50_value is not None else None
            ),
        )
        momentum_confirmed = None
        if macd_value is not None or volume_ratio is not None:
            momentum_confirmed = bool(
                (macd_value is not None and macd_value >= 0)
                or (volume_ratio is not None and volume_ratio >= 1.0)
            )
        add_check(
            'Momentum confirmation',
            momentum_confirmed,
            'non-negative MACD histogram or relative volume at least 1.0x',
            observed=(
                f'MACD {macd_value:.4f}' if macd_value is not None
                else (f'volume {volume_ratio:.2f}x' if volume_ratio is not None else None)
            ),
        )

    required_checks = [check for check in checks if check['required']]
    missing = [check['name'] for check in required_checks if not check['available']]
    failed = [check['name'] for check in required_checks if check['available'] and not check['passed']]
    met = bool(required_checks) and not missing and not failed
    if in_zone is False:
        status = 'WAIT_ZONE'
    elif missing:
        status = 'NEED_DATA'
    elif met:
        status = 'CONFIRMED'
    else:
        status = 'WAIT_TRIGGER'
    reasons = []
    if missing:
        reasons.append('Missing required trigger evidence: ' + ', '.join(missing))
    if failed:
        reasons.append('Trigger checks not met: ' + ', '.join(failed))
    return {
        'eligible': True,
        'met': met,
        'status': status,
        'setupKind': setup_kind,
        'checks': checks,
        'missing': missing,
        'reasons': reasons,
    }


def _assess_entry_reward_geometry(entry, stop, target1, target2=None, min_rr=1.45):
    """Score structural targets as supplied; never move a target to manufacture R/R."""
    def number(value):
        try:
            if value in (None, ''):
                return None
            return float(value)
        except (TypeError, ValueError):
            return None

    entry_value = number(entry)
    stop_value = number(stop)
    target1_value = number(target1)
    target2_value = number(target2)
    min_rr_value = number(min_rr) or 1.45
    risk = (
        entry_value - stop_value
        if entry_value is not None and stop_value is not None and entry_value > stop_value > 0 else None
    )
    rr1 = (
        (target1_value - entry_value) / risk
        if risk and target1_value is not None and target1_value > entry_value else 0.0
    )
    rr2 = (
        (target2_value - entry_value) / risk
        if risk and target2_value is not None and target2_value > entry_value else 0.0
    )
    primary_valid = bool(risk and target1_value is not None and target1_value > entry_value)
    return {
        'valid': bool(risk and primary_valid),
        'riskPerShare': round(risk, 4) if risk else 0.0,
        'riskReward1': round(rr1, 2),
        'riskReward2': round(rr2, 2),
        'primaryTargetValid': primary_valid,
        'passesMinimum': primary_valid and rr1 >= min_rr_value,
        'minRiskReward': min_rr_value,
    }


def _build_entry_limit_preflight(
    plan_snapshot,
    quote,
    buying_power,
    fractionable=True,
    require_attached_protection=False,
    require_marketable=False,
    limit_offset_bps=None,
):
    """Reprice and resize an approved plan against the executable quote.

    The Entry Plan owns the zone, stop, target, and risk budget. The live quote
    owns the trigger and final limit price. The returned quantity never exceeds
    the plan size, risk budget, allocation cap, or buffered buying power.
    """
    import math

    def number(value, default=0.0):
        try:
            if value in (None, ''):
                return default
            return float(value)
        except (TypeError, ValueError):
            return default

    zone = plan_snapshot.get('entryZone') if isinstance(plan_snapshot.get('entryZone'), dict) else {}
    low = number(plan_snapshot.get('entryZoneLow', plan_snapshot.get('entryLow', zone.get('low'))))
    high = number(plan_snapshot.get('entryZoneHigh', plan_snapshot.get('entryHigh', zone.get('high'))))
    stop = number(plan_snapshot.get('stopLoss', plan_snapshot.get('stop')))
    target = number(plan_snapshot.get('takeProfit1', plan_snapshot.get('takeProfit', plan_snapshot.get('target'))))
    planned_shares = number(plan_snapshot.get('shares', plan_snapshot.get('positionSizeShares')))
    risk_budget = number(plan_snapshot.get('riskBudget'), number(plan_snapshot.get('riskDollars')))
    max_allocation = number(plan_snapshot.get('maxAllocationDollars'), number(plan_snapshot.get('allocationDollars')))
    plan_slippage_bps = max(0.0, min(50.0, number(plan_snapshot.get('slippageCapBps'), 18.0)))
    configured_offset_bps = number(limit_offset_bps, plan_slippage_bps)
    slippage_bps = max(0.0, min(plan_slippage_bps, configured_offset_bps, 50.0))
    bid = number(quote.get('bid'))
    ask = number(quote.get('ask'))
    last = number(quote.get('last'))

    blockers = []
    if low <= 0 or high <= 0 or high < low:
        blockers.append('Entry zone unavailable or invalid')
    if bid <= 0 or ask <= 0 or ask < bid:
        blockers.append('Fresh executable bid/ask quote unavailable')
    if stop <= 0 or target <= 0:
        blockers.append('Stop loss or target unavailable')
    if planned_shares <= 0:
        blockers.append('Planned position size is zero')
    if buying_power <= 0:
        blockers.append('Available buying power is zero')
    if blockers:
        return {'ok': False, 'blockers': blockers}

    # A buy is triggered by the executable ask, not a stale last-trade marker.
    if not (low <= ask <= high):
        return {
            'ok': False,
            'code': 'price_outside_zone',
            'blockers': [f'Executable ask ${ask:.4f} is outside entry zone ${low:.4f}-${high:.4f}'],
            'quote': {'bid': bid, 'ask': ask, 'last': last},
        }

    midpoint = (bid + ask) / 2.0
    zone_cap = _entry_round_price(high, 'down')
    slippage_cap = _entry_round_price(midpoint * (1 + slippage_bps / 10000.0), 'down')
    marketable_ask = _entry_round_price(ask, 'up')
    limit_price = max(_entry_round_price(low, 'up'), min(zone_cap, slippage_cap, marketable_ask))
    limit_price = _entry_round_price(limit_price, 'down')
    marketable = limit_price + (_entry_price_tick(limit_price) / 10.0) >= ask

    if require_marketable and not marketable:
        return {
            'ok': False,
            'code': 'non_marketable_auto_limit',
            'blockers': [
                'Automatic entry requires a marketable limit; the slippage cap is below the executable ask.'
            ],
            'limitPrice': limit_price,
            'quote': {'bid': bid, 'ask': ask, 'last': last},
        }

    risk_per_share = limit_price - stop
    if risk_per_share <= 0:
        return {
            'ok': False,
            'code': 'invalid_risk_geometry',
            'blockers': [f'Limit ${limit_price:.4f} must be above stop ${stop:.4f}'],
        }
    if target <= limit_price:
        return {
            'ok': False,
            'code': 'invalid_risk_geometry',
            'blockers': [f'Target ${target:.4f} must be above limit ${limit_price:.4f}'],
        }

    buying_power_buffer_pct = max(
        0.0, min(25.0, number(plan_snapshot.get('buyingPowerBufferPct'), 5.0))
    )
    caps = [planned_shares, (buying_power * (1.0 - buying_power_buffer_pct / 100.0)) / limit_price]
    if risk_budget > 0:
        caps.append(risk_budget / risk_per_share)
    if max_allocation > 0:
        caps.append(max_allocation / limit_price)
    executable_shares = max(0.0, min(caps))

    # Whole-share plans can use Alpaca bracket protection. Keep genuinely small
    # positions fractional instead of inflating them to one share.
    use_bracket = executable_shares >= 1.0
    if require_attached_protection and not use_bracket:
        return {
            'ok': False,
            'code': 'fractional_protection_unavailable',
            'blockers': [
                'Automatic entry requires at least one whole share so stop and target can be attached as a bracket order.'
            ],
        }
    if use_bracket or not fractionable:
        executable_shares = float(math.floor(executable_shares))
    else:
        executable_shares = round(executable_shares, 4)

    min_shares = 0.01 if fractionable else 1.0
    if executable_shares < min_shares or executable_shares * limit_price < 1.0:
        return {
            'ok': False,
            'code': 'position_below_minimum',
            'blockers': ['Risk and allocation caps leave no executable position size'],
        }

    rounded_stop = _entry_round_price(stop, 'down')
    rounded_target = _entry_round_price(target, 'down')
    entry_tick = _entry_price_tick(limit_price)
    if rounded_stop > limit_price - entry_tick or rounded_target < limit_price + entry_tick:
        return {
            'ok': False,
            'code': 'invalid_risk_geometry',
            'blockers': [
                'Rounded stop/target must remain at least one price increment outside the entry limit'
            ],
        }

    spread_bps = ((ask - bid) / midpoint * 10000.0) if midpoint > 0 else None
    return {
        'ok': True,
        'limitPrice': limit_price,
        'shares': executable_shares,
        'notional': round(executable_shares * limit_price, 2),
        'riskDollars': round(executable_shares * risk_per_share, 2),
        'riskPerShare': round(risk_per_share, 4),
        'marketable': marketable,
        'orderClass': 'bracket' if use_bracket else 'simple',
        'protectionMode': 'alpaca_bracket' if use_bracket else 'exit_scan',
        'quote': {
            'bid': bid,
            'ask': ask,
            'last': last,
            'mid': round(midpoint, 4),
            'spreadBps': round(spread_bps, 2) if spread_bps is not None else None,
        },
        'entryZone': {'low': low, 'high': high},
        'stopLoss': rounded_stop,
        'takeProfit': rounded_target,
        'slippageCapBps': slippage_bps,
        'buyingPowerBufferPct': buying_power_buffer_pct,
    }


def _alpaca_order_error(response):
    """Normalize Alpaca order failures without hiding the broker's useful reason."""
    status = int(getattr(response, 'status_code', 0) or 0)
    raw_text = str(getattr(response, 'text', '') or '')[:500]
    body = {}
    try:
        body = response.json() if raw_text else {}
    except Exception:
        body = {}
    if not isinstance(body, dict):
        body = {}
    broker_code = body.get('code')
    broker_message = str(body.get('message') or raw_text or 'Order request was rejected')[:300]
    lowered = broker_message.lower()
    code = 'alpaca_order_rejected'
    retryable = status == 429 or status >= 500
    if broker_code == 40010001 or 'client_order_id must be unique' in lowered:
        code = 'duplicate_client_order_id'
    elif 'insufficient buying power' in lowered or 'buying power' in lowered:
        code = 'insufficient_buying_power'
    elif 'wash trade' in lowered:
        code = 'wash_trade_detected'
    elif 'available' in lowered and ('qty' in lowered or 'quantity' in lowered):
        code = 'insufficient_position_quantity'
    elif 'sub-penny' in lowered or 'minimum pricing criteria' in lowered:
        code = 'invalid_price_increment'
    elif status in (401, 403):
        code = 'broker_auth_or_account_blocked'
    elif status == 429:
        code = 'broker_rate_limited'
    elif status >= 500:
        code = 'broker_temporarily_unavailable'
    elif status == 422:
        code = 'invalid_order_parameters'
    return {
        'code': code,
        'brokerCode': broker_code,
        'brokerMessage': broker_message,
        'httpStatus': status,
        'retryable': retryable,
    }


def _count_daily_filled_orders(orders, now=None):
    """Count unique broker orders filled on the current New York session day."""
    now_et = _pa_as_et(now or datetime.now(timezone.utc))
    seen = set()
    count = 0
    for order in _pa_flatten_alpaca_order_tree(orders or []):
        if str(order.get('status') or '').lower() != 'filled':
            continue
        order_id = str(order.get('id') or order.get('client_order_id') or '')
        if not order_id or order_id in seen:
            continue
        filled_at = _pa_parse_timestamp(order.get('filled_at') or order.get('updated_at'))
        if filled_at is None or _pa_as_et(filled_at).date() != now_et.date():
            continue
        seen.add(order_id)
        count += 1
    return count


@app.route('/api/entry-plan/execute', methods=['POST'])
def entry_plan_execute():
    """
    Execute an entry plan order via Alpaca broker.
    Requires BUY_READY + all safety gates passed + broker connected.
    Entry Plan execution is limit-only. Automatic orders require an open market,
    a fresh executable quote inside the approved zone, and a clean pre-trade gate.
    """
    import requests as _req
    import time as _time
    import json as _json

    try:
        data = request.get_json()
        if not data:
            return jsonify({'success': False, 'action': 'BLOCKED', 'reason': 'No data provided', 'blockers': ['Empty request']}), 400
        user = get_supabase_user()
        if not user:
            return jsonify({
                'success': False,
                'action': 'BLOCKED',
                'reason': 'Authentication required',
                'blockers': ['Authentication required'],
            }), 401
        suppress_discord = bool(data.get('suppressDiscord'))

        symbol = data.get('symbol', '').upper().strip()
        plan_snapshot = data.get('planSnapshot', {})
        execution_mode = data.get('executionMode', 'recommend_only').strip().lower()
        if execution_mode != 'recommend_only':
            try:
                execution_mode = _operations_normalize_trading_mode(execution_mode)
            except ValueError as exc:
                return jsonify({
                    'success': False,
                    'action': 'BLOCKED',
                    'code': 'invalid_trading_mode',
                    'reason': str(exc),
                    'blockers': [str(exc)],
                }), 400
            if execution_mode == 'real':
                execution_mode = 'live'

        if not symbol:
            return jsonify({'success': False, 'action': 'BLOCKED', 'reason': 'Symbol required', 'blockers': ['No symbol']}), 400

        if execution_mode == 'live':
            aal_error = _require_aal2(user, allow_headless_live_authority=True)
            if aal_error:
                return aal_error

        # ── 1. Verify plan snapshot exists ──
        if not plan_snapshot:
            return jsonify({'success': False, 'action': 'BLOCKED', 'symbol': symbol, 'reason': 'No plan snapshot provided', 'blockers': ['Missing planSnapshot']}), 400

        # ── 2. Verify all required gates ──
        blockers = []
        submitted_policy = plan_snapshot.get('strategyPolicy') if isinstance(plan_snapshot.get('strategyPolicy'), dict) else {}
        # Execution never trusts client-supplied percentages. Rebuild the
        # mandate server-side, where platform hard caps are applied.
        strategy_policy = _apply_account_hard_risk_limits(
            _strategy_policy(
                plan_snapshot.get('riskProfileUsed') or submitted_policy.get('riskProfile') or 'medium',
                plan_snapshot.get('timeHorizonUsed') or submitted_policy.get('timeHorizon') or 'mid',
                plan_snapshot.get('pipelineModeUsed') or submitted_policy.get('pipelineMode') or 'hybrid',
                bool(submitted_policy.get('leverageEnabled', False)),
            ),
            user['id'],
        )
        workspace_preferences = _pa_workspace_preferences(_pa_get_config(user['id']) or {})
        workspace_risk_preferences = workspace_preferences.get('risk') or {}
        quote_freshness_seconds = int(workspace_risk_preferences.get('staleQuoteSeconds') or 45)
        block_on_stale_quote = workspace_risk_preferences.get('blockOnStaleQuote') is not False
        instrument_type = str(
            plan_snapshot.get('instrumentType')
            or plan_snapshot.get('assetClass')
            or plan_snapshot.get('securityType')
            or ''
        ).strip().lower()
        if instrument_type in ('option', 'options', 'us_option') or plan_snapshot.get('optionsAllowed') is True:
            blockers.append('Options are prohibited by the AlphaLab strategy mandate')
        if strategy_policy and strategy_policy.get('optionsAllowed') is not False:
            blockers.append('Strategy mandate must explicitly prohibit options before execution')
        final_action = plan_snapshot.get('finalAction', '')
        risk_gate = plan_snapshot.get('riskGate', plan_snapshot.get('hardRiskGate', {}))
        risk_gate_status = risk_gate.get('status', 'BLOCK')
        data_quality = plan_snapshot.get('dataQuality', 'POOR')
        trade_readiness = plan_snapshot.get('tradeReadiness', 'BLOCKED')
        is_auto_execute = data.get('isAutoExecute', False)
        try:
            shares = float(plan_snapshot.get('shares', plan_snapshot.get('positionSizeShares', 0)) or 0)
        except (TypeError, ValueError):
            shares = 0
        order_preview = (
            plan_snapshot.get('orderPreview', {})
            or (plan_snapshot.get('executionDetails', {}) or {}).get('orderPreview', {})
            or ((plan_snapshot.get('institutionalEntryPlan', {}) or {}).get('execution', {}) if isinstance(plan_snapshot.get('institutionalEntryPlan'), dict) else {})
            or {}
        )
        # Entry Plan is intentionally limit-only. Any legacy market/stop-limit
        # suggestion is repriced from a fresh quote before submission.
        order_type = 'limit'
        time_in_force = plan_snapshot.get('timeInForce', order_preview.get('timeInForce', 'day'))
        def _as_float(v, default=0):
            try:
                if v is None or v == '':
                    return default
                return float(v)
            except (TypeError, ValueError):
                return default
        entry_zone = plan_snapshot.get('entryZone') if isinstance(plan_snapshot.get('entryZone'), dict) else {}
        entry_low = _as_float(plan_snapshot.get('entryZoneLow', plan_snapshot.get('entryLow', entry_zone.get('low'))))
        entry_high = _as_float(plan_snapshot.get('entryZoneHigh', plan_snapshot.get('entryHigh', entry_zone.get('high'))))
        current_price = _as_float(plan_snapshot.get('currentPrice', plan_snapshot.get('price')))
        stop_loss_plan = _as_float(plan_snapshot.get('stopLoss', plan_snapshot.get('stop')))
        take_profit_plan = _as_float(plan_snapshot.get('takeProfit1', plan_snapshot.get('takeProfit', plan_snapshot.get('target'))))

        # B9: Explicitly reject GTC for buy orders — all buy orders must be day
        if time_in_force and str(time_in_force).lower() == 'gtc':
            blockers.append('GTC time-in-force is not allowed for buy orders. Entry Plan orders must use day orders only.')

        if final_action != 'BUY_READY':
            blockers.append(f'finalAction is {final_action}, not BUY_READY')
        if risk_gate_status != 'PASS':
            blockers.append(f'Risk Gate status is {risk_gate_status}, not PASS')
        # Automated execution requires complete evidence. Manual review can still
        # inspect a PARTIAL plan, but it cannot be promoted by setting a flag here.
        if data_quality != 'GOOD':
            blockers.append(f'Data Quality is {data_quality}, not GOOD')
        if trade_readiness != 'READY':
            blockers.append(f'Trade Readiness is {trade_readiness}, not READY')
        if plan_snapshot.get('setupAutoEligible') is not True:
            blockers.append('Setup is not eligible for automatic entry')
        if plan_snapshot.get('entryTriggerMet') is not True:
            blockers.append('Setup-specific entry trigger is not confirmed')
        trigger_status = str(plan_snapshot.get('entryTriggerStatus') or '').upper()
        if trigger_status != 'CONFIRMED':
            blockers.append(f'Entry trigger status is {trigger_status or "unavailable"}, not CONFIRMED')
        trigger_age_seconds = _entry_quote_age_seconds(plan_snapshot.get('triggerEvaluatedAt'))
        if is_auto_execute and (trigger_age_seconds is None or trigger_age_seconds > 300):
            blockers.append('Entry trigger evaluation is stale; rerun Entry Plan before automatic execution')
        admission_decision = str(plan_snapshot.get('admissionDecision') or '').upper()
        admission_snapshot = plan_snapshot.get('admissionSnapshot') if isinstance(plan_snapshot.get('admissionSnapshot'), dict) else {}
        if is_auto_execute:
            if admission_decision != 'ADMIT':
                blockers.append('Portfolio Admission is not ADMIT')
            if not admission_snapshot.get('id') or not admission_snapshot.get('inputFingerprint'):
                blockers.append('Portfolio Admission snapshot is unavailable')
            admission_expiry = _pa_parse_timestamp(admission_snapshot.get('expiresAt'))
            if admission_expiry is None or admission_expiry.astimezone(timezone.utc) <= datetime.now(timezone.utc):
                blockers.append('Portfolio Admission snapshot is expired; rerun validation')
            locked_strategy = _pa_normalize_strategy(admission_snapshot.get('strategy'))
            plan_strategy = _pa_normalize_strategy(plan_snapshot.get('strategy') or plan_snapshot.get('bestStrategy') or plan_snapshot.get('setup'))
            if locked_strategy and plan_strategy and locked_strategy != plan_strategy:
                blockers.append('Entry Plan strategy differs from the admitted strategy version')
        if shares <= 0:
            blockers.append(f'Shares is {shares}, must be > 0')
        # Build order preview from plan fields if missing (leveraged alternatives may lack it)
        if not order_preview:
            _op_limit = min(current_price, entry_high) if current_price > 0 and entry_high > 0 else (current_price or entry_high or 0)
            order_preview = {'orderType': 'limit', 'limitPrice': _op_limit, 'timeInForce': 'day',
                             'entryZoneLow': entry_low, 'entryZoneHigh': entry_high}
        order_preview['orderType'] = 'limit'
        if entry_low <= 0 or entry_high <= 0:
            blockers.append('Entry zone unavailable')
        if stop_loss_plan <= 0:
            blockers.append('Stop loss unavailable')
        if take_profit_plan <= 0:
            blockers.append('Target price unavailable')
        # Do not gate on the generation-time snapshot. A fresh executable ask is
        # fetched immediately before submission and owns the final zone decision.

        if blockers:
            # Classify blocker for frontend status display
            _blocker_code = 'safety_gate'
            _blockers_lower = ' '.join(blockers).lower()
            if 'existing position' in _blockers_lower:
                _blocker_code = 'existing_position'
            elif 'open buy order' in _blockers_lower:
                _blocker_code = 'open_buy_order'
            elif 'outside entry zone' in _blockers_lower:
                _blocker_code = 'price_outside_zone'
            elif 'buying power' in _blockers_lower or 'exceeds' in _blockers_lower:
                _blocker_code = 'insufficient_buying_power'
            elif 'not configured' in _blockers_lower or 'api key' in _blockers_lower:
                _blocker_code = 'config_missing'
            print(f'[ENTRY EXECUTE] {symbol} BLOCKED code={_blocker_code}: {blockers}')
            if user and not suppress_discord:
                send_discord_notification(user['id'], 'error', {
                    'event_id': f'entry-execute-blocked-{symbol}-{int(time.time())}',
                    'step': 'Entry Plan Execute',
                    'status': 'blocked',
                    'symbol': symbol,
                    'reason': '; '.join(blockers)[:300],
                    'action': 'Review risk gate, data quality, and trade readiness.',
                })
            return jsonify({
                'success': False, 'action': 'BLOCKED', 'symbol': symbol,
                'code': _blocker_code,
                'reason': '; '.join(blockers)[:300] if blockers else 'Safety gates not passed',
                'blockers': blockers
            })

        # ── 3. Check execution mode ──
        if execution_mode == 'recommend_only':
            if user and not suppress_discord:
                send_discord_notification(user['id'], 'error', {
                    'event_id': f'entry-execute-review-only-{symbol}-{int(time.time())}',
                    'step': 'Entry Plan Execute',
                    'status': 'blocked',
                    'symbol': symbol,
                    'reason': 'Recommend Only mode - no order placement allowed',
                    'action': 'Switch execution mode only if you intend to submit orders.',
                })
            return jsonify({
                'success': False, 'action': 'BLOCKED', 'symbol': symbol,
                'reason': 'Recommend Only mode — no order placement allowed',
                'blockers': ['executionMode is recommend_only']
            })

        if is_auto_execute:
            saved_automation = _pa_get_config(user['id']) or {}
            order_authority = _pa_order_authority(
                saved_automation,
                mode=saved_automation.get('mode'),
                trade_mode='real' if execution_mode == 'live' else 'paper',
            )
            if not order_authority.get('buyAuthorized'):
                return jsonify({
                    'success': False,
                    'action': 'BLOCKED',
                    'symbol': symbol,
                    'code': order_authority.get('code') or 'order_authority_locked',
                    'reason': order_authority.get('message') or 'Automatic buy authority is locked.',
                    'blockers': [order_authority.get('message') or 'Automatic buy authority is locked.'],
                    'orderAuthority': order_authority,
                }), 403

        # Unattended live execution must first have the user's explicit
        # authorization. Only after that intent is established do we consult
        # the global durable safety lock (which still fails closed for live
        # orders when its backing store is unavailable).
        if execution_mode == 'live' and is_auto_execute:
            automation_config = _pa_get_config(user['id']) or {}
            if automation_config.get('live_auto_trading_enabled') is not True:
                return jsonify({
                    'success': False,
                    'action': 'BLOCKED',
                    'symbol': symbol,
                    'code': 'live_auto_not_enabled',
                    'reason': 'Live background auto trading is not explicitly enabled',
                    'blockers': ['Enable Live Auto Trading in the automation controls before unattended real orders'],
                })

        safety_block = _operations_buy_submission_block(user['id'], execution_mode)
        if safety_block:
            return jsonify({
                'success': False,
                'action': 'BLOCKED',
                'symbol': symbol,
                'blockers': [safety_block['message']],
                **safety_block,
            }), 423

        # ── 4. Live mode: auto-execute bypasses confirmation; manual requires it ──
        if execution_mode == 'live' and not is_auto_execute:
            live_confirm = data.get('liveConfirm', False)
            confirm_text = data.get('confirmText', '')
            expected_text = f'CONFIRM LIVE BUY {symbol}'
            if not live_confirm or confirm_text.strip().upper() != expected_text.upper():
                return jsonify({
                    'success': False, 'action': 'BLOCKED', 'symbol': symbol,
                    'reason': 'Live trading requires explicit confirmation',
                    'blockers': ['liveConfirm missing or confirmText mismatch']
                })
        # ── 5. Connect to Alpaca broker (from per-user Supabase config) ──
        alpaca_mode = 'live' if execution_mode == 'live' else 'paper'
        alpaca_cfg, alpaca_src = resolve_alpaca_config(alpaca_mode, require_user_config=True)
        api_key = alpaca_cfg.get('api_key', '')
        api_secret = alpaca_cfg.get('api_secret', '')
        base_url = alpaca_cfg.get('base_url', 'https://paper-api.alpaca.markets' if alpaca_mode == 'paper' else 'https://api.alpaca.markets')
        mode_label = alpaca_mode

        if not api_key or not api_secret:
            return jsonify({
                'success': False, 'action': 'BLOCKED', 'symbol': symbol,
                'reason': f'Alpaca {mode_label} API keys not configured',
                'blockers': ['Broker API keys not configured']
            })

        headers = {
            'APCA-API-KEY-ID': api_key,
            'APCA-API-SECRET-KEY': api_secret,
            'Content-Type': 'application/json'
        }

        # ── 6. Fresh market preflight ──
        market_clock = {}
        try:
            clock_resp = _req.get(f'{base_url}/v2/clock', headers=headers, timeout=8)
            if clock_resp.status_code == 200:
                market_clock = clock_resp.json() or {}
            elif is_auto_execute:
                blockers.append(f'Cannot verify market clock: HTTP {clock_resp.status_code}')
        except Exception as clock_error:
            if is_auto_execute:
                blockers.append(f'Cannot verify market clock: {str(clock_error)[:80]}')

        if market_clock.get('is_open') is not True:
            next_open = market_clock.get('next_open')
            suffix = f' Next open: {next_open}.' if next_open else ''
            blockers.append(f'Market is closed; Entry Plan orders are not queued overnight.{suffix}')

        quote_packet = {}
        quote_age_seconds = None
        try:
            market_cfg, _ = resolve_alpaca_config('market_data', require_user_config=True)
            market_headers = {
                'APCA-API-KEY-ID': market_cfg.get('api_key', ''),
                'APCA-API-SECRET-KEY': market_cfg.get('api_secret', ''),
            }
            if not market_headers['APCA-API-KEY-ID'] or not market_headers['APCA-API-SECRET-KEY']:
                blockers.append('Alpaca Market Data credentials are not configured')
            else:
                snapshot_resp = _req.get(
                    f'{_get_market_data_base_url()}/v2/stocks/{symbol}/snapshot',
                    headers=market_headers,
                    timeout=10,
                )
                if snapshot_resp.status_code == 200:
                    snapshot = snapshot_resp.json() or {}
                    latest_quote = snapshot.get('latestQuote') or {}
                    latest_trade = snapshot.get('latestTrade') or {}
                    quote_packet = {
                        'bid': _as_float(latest_quote.get('bp')),
                        'ask': _as_float(latest_quote.get('ap')),
                        'bidSize': _as_float(latest_quote.get('bs')),
                        'askSize': _as_float(latest_quote.get('as')),
                        'last': _as_float(latest_trade.get('p')),
                        'timestamp': latest_quote.get('t') or latest_trade.get('t'),
                        'feed': snapshot.get('feed') or 'Alpaca Market Data snapshot',
                    }
                    quote_age_seconds = _entry_quote_age_seconds(quote_packet.get('timestamp'))
                else:
                    blockers.append(f'Fresh Alpaca quote unavailable: HTTP {snapshot_resp.status_code}')
        except Exception as quote_error:
            blockers.append(f'Fresh Alpaca quote unavailable: {str(quote_error)[:100]}')

        if not quote_packet.get('bid') or not quote_packet.get('ask'):
            blockers.append('Fresh executable bid/ask quote unavailable')
        if is_auto_execute and block_on_stale_quote and market_clock.get('is_open') is True:
            if quote_age_seconds is None:
                blockers.append('Quote timestamp unavailable; automatic execution requires freshness verification')
            elif quote_age_seconds > quote_freshness_seconds:
                blockers.append(
                    f'Quote is stale ({quote_age_seconds:.0f}s old); automatic execution '
                    f'requires <= {quote_freshness_seconds}s'
                )

        if blockers:
            blocker_text = ' '.join(blockers).lower()
            if 'market is closed' in blocker_text:
                blocker_code = 'market_closed'
            elif 'stale' in blocker_text:
                blocker_code = 'stale_quote'
            else:
                blocker_code = 'quote_unavailable'
            return jsonify({
                'success': False,
                'action': 'BLOCKED',
                'symbol': symbol,
                'code': blocker_code,
                'reason': '; '.join(blockers)[:300],
                'blockers': blockers,
                'marketClock': market_clock,
                'quote': quote_packet,
            })

        # ── 7. Check buying power, account state, position, and open orders ──
        _bp_check_passed = True
        _existing_position_found = False
        _open_buy_order_found = False
        _open_sell_order_found = False
        buying_power = 0.0
        spendable_buying_power = 0.0
        cash = 0.0
        non_marginable_buying_power = 0.0
        equity = 0.0
        last_equity = 0.0
        current_position_count = 0
        open_buy_order_count = 0
        daily_filled_order_count = None
        existing_symbol_market_value = 0.0
        sector_market_values = {}
        fractionable = bool(plan_snapshot.get('fractionable', True))
        try:
            acc_resp = _req.get(f'{base_url}/v2/account', headers=headers, timeout=10)
            if acc_resp.status_code == 200:
                acc_data = acc_resp.json()
                buying_power = float(acc_data.get('buying_power', 0))
                cash = float(acc_data.get('cash', 0))
                non_marginable_buying_power = float(acc_data.get('non_marginable_buying_power', 0) or 0)
                equity = float(acc_data.get('equity', 0))
                last_equity = float(acc_data.get('last_equity', 0) or 0)
                # Legacy plan fields cannot activate borrowing. Margin is usable
                # only when the signed strategy mandate explicitly allows the
                # high-risk, short-horizon leveraged sleeve.
                allow_margin = bool(
                    strategy_policy.get('leverageEnabled') is True
                    and plan_snapshot.get('allowMargin') is True
                )
                cash_capacity = max(cash, non_marginable_buying_power, 0.0)
                spendable_buying_power = buying_power if allow_margin else min(buying_power, cash_capacity)
                if acc_data.get('trading_blocked') or acc_data.get('account_blocked') or acc_data.get('trade_suspended_by_user'):
                    blockers.append('Alpaca account is currently blocked or trading is suspended')
                    _bp_check_passed = False
                if spendable_buying_power <= 0:
                    blockers.append('Available cash-funded buying power is zero')
                    _bp_check_passed = False
                if last_equity > 0 and equity > 0:
                    session_loss_pct = max(0.0, (last_equity - equity) / last_equity * 100.0)
                    daily_loss_stop_pct = _as_float(strategy_policy.get('dailyLossStopPct'), 2.5)
                    daily_loss_stop_pct = min(max(daily_loss_stop_pct, 0.5), 4.0)
                    if session_loss_pct >= daily_loss_stop_pct:
                        blockers.append(
                            f'Account session loss {session_loss_pct:.2f}% reached the '
                            f'{daily_loss_stop_pct:.1f}% strategy kill switch'
                        )
                        _bp_check_passed = False
            else:
                blockers.append(f'Cannot verify buying power: HTTP {acc_resp.status_code}')
                _bp_check_passed = False
        except Exception as acc_e:
            blockers.append(f'Cannot verify buying power: {str(acc_e)[:80]}')
            _bp_check_passed = False

        try:
            asset_resp = _req.get(f'{base_url}/v2/assets/{symbol}', headers=headers, timeout=8)
            if asset_resp.status_code == 200:
                asset_data = asset_resp.json() or {}
                fractionable = bool(asset_data.get('fractionable', fractionable))
                asset_class = str(asset_data.get('class') or asset_data.get('asset_class') or '').strip().lower()
                if asset_class not in ('us_equity', ''):
                    blockers.append(
                        f'{symbol} asset class {asset_class or "unknown"} is outside the US-equity-only mandate'
                    )
                if not asset_data.get('tradable', True) or asset_data.get('status') not in (None, 'active'):
                    blockers.append(f'{symbol} is not active and tradable in Alpaca {alpaca_mode}')
            else:
                blockers.append(f'Cannot verify asset tradability: HTTP {asset_resp.status_code}')
        except Exception as asset_error:
            blockers.append(f'Cannot verify asset tradability: {str(asset_error)[:80]}')

        try:
            pos_resp = _req.get(f'{base_url}/v2/positions', headers=headers, timeout=10)
            if pos_resp.status_code == 200:
                position_rows = pos_resp.json() or []
                current_position_count = len(position_rows)
                for position in position_rows:
                    position_symbol = str(position.get('symbol', '')).upper()
                    position_market_value = abs(_as_float(position.get('market_value')))
                    managed_position = _pa_get_managed_position_plan(
                        user['id'], mode_label, position_symbol,
                    ) or {}
                    position_sector = str(
                        managed_position.get('sector')
                        or (plan_snapshot.get('sector') if position_symbol == symbol else '')
                        or 'Unknown'
                    ).strip() or 'Unknown'
                    sector_market_values[position_sector.lower()] = (
                        sector_market_values.get(position_sector.lower(), 0.0)
                        + position_market_value
                    )
                    if position_symbol != symbol:
                        continue
                    pos_qty = _as_float(position.get('qty'))
                    if pos_qty > 0:
                        _existing_position_found = True
                        existing_symbol_market_value = position_market_value
                        if str(plan_snapshot.get('entryIntent') or '').upper() != 'SCALE_IN':
                            blockers.append(f'Existing position already held for {symbol} ({pos_qty} shares)')
                        else:
                            fresh_market_value = abs(_as_float(position.get('market_value')))
                            total_position_cap = _as_float(plan_snapshot.get('maxTotalPositionDollars'))
                            if total_position_cap > 0:
                                fresh_remaining = max(0.0, total_position_cap - fresh_market_value)
                                planned_increment = _as_float(plan_snapshot.get('maxAllocationDollars'))
                                plan_snapshot['maxAllocationDollars'] = min(planned_increment, fresh_remaining)
                                plan_snapshot['freshExistingPositionValue'] = fresh_market_value
                                plan_snapshot['freshRemainingPositionCapacityDollars'] = fresh_remaining
                                if fresh_remaining < 1.0:
                                    blockers.append('Existing position already uses the full per-symbol allocation limit')
                max_positions = int(_as_float(plan_snapshot.get('maxPortfolioPositions'), 0))
                if max_positions > 0 and not _existing_position_found and current_position_count + 1 > max_positions:
                    blockers.append(
                        f'Portfolio position limit reached ({current_position_count}/{max_positions})'
                    )
            else:
                blockers.append(f'Cannot verify existing positions: HTTP {pos_resp.status_code}')
        except Exception as pos_e:
            blockers.append(f'Cannot verify existing positions: {str(pos_e)[:80]}')

        try:
            ord_resp = _req.get(
                f'{base_url}/v2/orders', headers=headers,
                params={'status': 'open', 'nested': 'true', 'limit': 500}, timeout=10,
            )
            if ord_resp.status_code == 200:
                symbol_sell_orders = []
                for order in _pa_flatten_alpaca_order_tree(ord_resp.json() or []):
                    order_side = str(order.get('side', '')).lower()
                    order_symbol = str(order.get('symbol', '')).upper()
                    if order_side == 'sell' and order_symbol == symbol:
                        _open_sell_order_found = True
                        symbol_sell_orders.append(order)
                    if order_side != 'buy':
                        continue
                    open_buy_order_count += 1
                    if str(order.get('symbol', '')).upper() == symbol:
                        blockers.append(f'Open buy order already exists for {symbol}')
                        _open_buy_order_found = True
                max_open_buys = int(_as_float(plan_snapshot.get('maxOpenBuyOrders'), 0))
                if max_open_buys > 0 and not _open_buy_order_found and open_buy_order_count >= max_open_buys:
                    blockers.append(
                        f'Open buy order limit reached ({open_buy_order_count}/{max_open_buys})'
                    )
                # A managed stop/target protects the quantity already held; it
                # must not make every scale-in permanently unreachable.  Keep
                # the existing protection in place while the add order is open.
                # After a fill, Position Guard detects partial stop coverage and
                # atomically replaces AlphaLab-owned protection for the new
                # broker position quantity.  External sell orders remain broker
                # owned and are never cancelled here.
                if (
                    str(plan_snapshot.get('entryIntent') or '').upper() == 'SCALE_IN'
                    and _open_sell_order_found
                ):
                    scale_in_protection = _pa_scale_in_protection_gate(symbol_sell_orders)
                    if not scale_in_protection.get('eligible'):
                        blockers.extend(scale_in_protection.get('blockers') or [])
                    else:
                        plan_snapshot['protectionRefreshRequired'] = bool(
                            scale_in_protection.get('refreshRequired')
                        )
            else:
                blockers.append(f'Cannot verify open orders: HTTP {ord_resp.status_code}')
        except Exception as ord_e:
            blockers.append(f'Cannot verify open orders: {str(ord_e)[:80]}')

        try:
            day_start_et = _pa_now_et().replace(hour=0, minute=0, second=0, microsecond=0)
            closed_resp = _req.get(
                f'{base_url}/v2/orders',
                headers=headers,
                params={
                    'status': 'closed',
                    'after': day_start_et.astimezone(timezone.utc).isoformat(),
                    'direction': 'desc',
                    'nested': 'false',
                    'limit': 500,
                },
                timeout=10,
            )
            if closed_resp.status_code == 200:
                daily_filled_order_count = _count_daily_filled_orders(
                    closed_resp.json() or [], now=datetime.now(timezone.utc),
                )
                daily_order_cap = int(strategy_policy['maxDailyFilledOrders'])
                if daily_filled_order_count >= daily_order_cap:
                    blockers.append(
                        f'Daily filled-order limit reached '
                        f'({daily_filled_order_count}/{daily_order_cap})'
                    )
            else:
                blockers.append(
                    f'Cannot verify daily filled-order limit: HTTP {closed_resp.status_code}'
                )
        except Exception as daily_orders_error:
            blockers.append(
                f'Cannot verify daily filled-order limit: {str(daily_orders_error)[:80]}'
            )

        # Server-owned limits replace all client-provided budget fields.
        if equity <= 0:
            blockers.append('Account equity is unavailable for platform risk-limit verification')
        else:
            hard_risk_budget = equity * strategy_policy['riskPerTradePct'] / 100.0
            hard_position_budget = equity * strategy_policy['maxSinglePositionPct'] / 100.0
            plan_snapshot['riskBudget'] = min(
                max(0.0, _as_float(plan_snapshot.get('riskBudget'), hard_risk_budget)),
                hard_risk_budget,
            )
            plan_snapshot['maxAllocationDollars'] = min(
                max(0.0, _as_float(plan_snapshot.get('maxAllocationDollars'), hard_position_budget)),
                max(0.0, hard_position_budget - existing_symbol_market_value),
            )
            plan_snapshot['maxTotalPositionDollars'] = hard_position_budget

        if blockers:
            # Build a specific reason with code for frontend status display
            if _existing_position_found and str(plan_snapshot.get('entryIntent') or '').upper() != 'SCALE_IN':
                reason = f'Existing position held for {symbol}'
                _code = 'existing_position'
            elif _open_buy_order_found:
                reason = f'Open buy order exists for {symbol}'
                _code = 'open_buy_order'
            elif not _bp_check_passed:
                reason = '; '.join(blockers)
                _code = 'insufficient_buying_power'
            else:
                reason = '; '.join(blockers)
                _code = 'verification_failed'
            return jsonify({
                'success': False, 'action': 'BLOCKED', 'symbol': symbol,
                'code': _code, 'reason': reason[:300], 'blockers': blockers
            })

        # ── 8. Reprice, resize, and submit a limit-only order ──
        preflight = _build_entry_limit_preflight(
            plan_snapshot,
            quote_packet,
            spendable_buying_power,
            fractionable=fractionable,
            require_attached_protection=is_auto_execute,
            require_marketable=is_auto_execute,
            limit_offset_bps=(workspace_preferences.get('trading') or {}).get('limitOffsetBps'),
        )
        if not preflight.get('ok'):
            preflight_blockers = preflight.get('blockers') or ['Execution preflight failed']
            return jsonify({
                'success': False,
                'action': 'BLOCKED',
                'symbol': symbol,
                'code': preflight.get('code') or 'execution_preflight',
                'reason': '; '.join(preflight_blockers)[:300],
                'blockers': preflight_blockers,
                'preflight': preflight,
                'marketClock': market_clock,
                'quoteAgeSeconds': round(quote_age_seconds, 1) if quote_age_seconds is not None else None,
            })

        # Last-moment dollar checks remain outside the sizing helper so future
        # changes to that helper cannot bypass account-level concentration caps.
        hard_position_budget = equity * strategy_policy['maxSinglePositionPct'] / 100.0
        candidate_notional = float(preflight.get('notional') or 0)
        maximum_order_notional = float(workspace_risk_preferences.get('maxOrderNotional') or 10000)
        if candidate_notional > maximum_order_notional + 0.01:
            return jsonify({
                'success': False,
                'action': 'BLOCKED',
                'symbol': symbol,
                'code': 'max_order_notional_exceeded',
                'reason': 'Account maximum order notional would be exceeded.',
                'blockers': ['Account maximum order notional would be exceeded.'],
                'maximumOrderNotional': maximum_order_notional,
                'candidateNotional': round(candidate_notional, 2),
            }), 409
        if existing_symbol_market_value + candidate_notional > hard_position_budget + 0.01:
            return jsonify({
                'success': False,
                'action': 'BLOCKED',
                'symbol': symbol,
                'code': 'single_position_hard_cap',
                'reason': 'Platform single-position hard cap would be exceeded.',
                'blockers': ['Platform single-position hard cap would be exceeded.'],
                'effectiveLimits': strategy_policy['effectiveLimits'],
            }), 409
        candidate_sector = str(plan_snapshot.get('sector') or 'Unknown').strip().lower() or 'unknown'
        hard_sector_budget = equity * strategy_policy['sectorCapPct'] / 100.0
        if sector_market_values.get(candidate_sector, 0.0) + candidate_notional > hard_sector_budget + 0.01:
            return jsonify({
                'success': False,
                'action': 'BLOCKED',
                'symbol': symbol,
                'code': 'sector_hard_cap',
                'reason': 'Platform sector concentration hard cap would be exceeded.',
                'blockers': ['Platform sector concentration hard cap would be exceeded.'],
                'effectiveLimits': strategy_policy['effectiveLimits'],
            }), 409
        hard_risk_budget = equity * strategy_policy['riskPerTradePct'] / 100.0
        if float(preflight.get('riskDollars') or 0) > hard_risk_budget + 0.01:
            return jsonify({
                'success': False,
                'action': 'BLOCKED',
                'symbol': symbol,
                'code': 'per_trade_risk_hard_cap',
                'reason': 'Platform per-trade risk hard cap would be exceeded.',
                'blockers': ['Platform per-trade risk hard cap would be exceeded.'],
                'effectiveLimits': strategy_policy['effectiveLimits'],
            }), 409

        limit_price = preflight['limitPrice']
        shares = preflight['shares']
        stop_loss = preflight['stopLoss']
        take_profit = preflight['takeProfit']
        order_class = preflight['orderClass']
        protection_mode = preflight['protectionMode']
        qty_value = str(int(shares)) if order_class == 'bracket' else ('%.4f' % shares).rstrip('0').rstrip('.')
        client_order_seed = (
            data.get('clientOrderId')
            or data.get('client_order_id')
            or request.headers.get('X-Idempotency-Key')
            or admission_snapshot.get('id')
            or plan_snapshot.get('id')
            or '%s:%s:%s:%s' % (
                plan_snapshot.get('triggerEvaluatedAt') or '',
                symbol,
                limit_price,
                shares,
            )
        )
        client_order_id = _operations_managed_buy_client_order_id(
            user['id'], symbol,
            client_order_seed,
        )

        order_payload = {
            'symbol': symbol,
            'side': 'buy',
            'qty': qty_value,
            'type': 'limit',
            'limit_price': str(limit_price),
            'time_in_force': 'day',
            'extended_hours': False,
            'client_order_id': str(client_order_id)[:48],
        }
        if order_class == 'bracket':
            order_payload.update({
                'order_class': 'bracket',
                'take_profit': {'limit_price': str(take_profit)},
                'stop_loss': {'stop_price': str(stop_loss)},
            })

        print(
            f'[ENTRY EXECUTE] {symbol}: submitting {mode_label} limit order '
            f'shares={shares} limit=${limit_price} class={order_class} '
            f'marketable={preflight.get("marketable")}'
        )

        safety_block = _operations_buy_submission_block(user['id'], execution_mode)
        if safety_block:
            return jsonify({
                'success': False,
                'action': 'BLOCKED',
                'status': 'safety_locked',
                'symbol': symbol,
                'blockers': [safety_block['message']],
                **safety_block,
            }), 423

        def _idempotent_existing_order_response(existing_order):
            existing_order_id = existing_order.get('id') or 'unknown'
            existing_status = existing_order.get('status') or 'unknown'
            _record_order_lifecycle(
                user['id'], existing_order_id, 'entry_idempotent_replay', existing_status,
                payload={
                    'mode': 'real' if mode_label == 'live' else 'paper',
                    'side': 'buy', 'symbol': symbol, 'type': 'limit',
                    'clientOrderId': client_order_id,
                },
            )
            return jsonify({
                'success': True,
                'action': 'ORDER_ALREADY_SUBMITTED',
                'symbol': symbol,
                'mode': mode_label,
                'orderId': existing_order_id,
                'orderStatus': existing_status,
                'order': existing_order,
                'orderData': existing_order,
                'submittedOrder': existing_order,
                'clientOrderId': client_order_id,
                'idempotentReplay': True,
                'message': 'The existing Alpaca order was returned; no duplicate order was submitted.',
            })

        existing_order, lookup_error = _alpaca_lookup_order_by_client_id(
            base_url, headers, client_order_id,
        )
        if existing_order:
            return _idempotent_existing_order_response(existing_order)
        if lookup_error and is_auto_execute:
            return jsonify({
                'success': False,
                'action': 'BLOCKED',
                'symbol': symbol,
                'code': 'idempotency_lookup_unavailable',
                'reason': 'Alpaca order idempotency could not be verified; automatic submission was blocked.',
                'blockers': ['Order idempotency lookup unavailable.'],
                'detail': lookup_error,
            }), 503

        order_resp = _req.post(f'{base_url}/v2/orders', headers=headers, json=order_payload, timeout=30)

        if order_resp.status_code in (200, 201):
            order_data = order_resp.json()
            order_id = order_data.get('id', 'unknown')
            order_status = order_data.get('status', 'unknown')
            print(f'[ENTRY EXECUTE] {symbol}: ORDER SUBMITTED id={order_id} status={order_status}')
            _record_order_lifecycle(
                user['id'], order_id, 'entry_submitted', order_status,
                payload={
                    'mode': 'real' if mode_label == 'live' else 'paper',
                    'side': 'buy', 'symbol': symbol, 'type': 'limit',
                    'orderClass': order_class, 'clientOrderId': order_data.get('client_order_id'),
                },
            )
            if user and not suppress_discord:
                send_discord_notification(user['id'], 'order', {
                    'event_id': order_id,
                    'mode': 'real' if mode_label == 'live' else 'paper',
                    'side': 'buy',
                    'symbol': symbol,
                    'qty': shares,
                    'orderType': 'limit',
                    'orderClass': order_class,
                    'limitPrice': limit_price,
                    'price': limit_price,
                    'status': order_status,
                    'orderId': order_id,
                    'reason': 'Entry Plan execution submitted order.',
                })
            if user:
                _pa_record_managed_position_plan(
                    user['id'], mode_label, symbol, plan_snapshot,
                    order=order_data, status='entry_submitted',
                )

            if order_class == 'bracket':
                note = (
                    f'Protected limit entry: target ${take_profit:.2f} and stop ${stop_loss:.2f} '
                    'will activate after the entry fills.'
                )
            else:
                note = (
                    f'Fractional limit entry submitted. Stop ${stop_loss:.2f} / target ${take_profit:.2f} '
                    'remain managed by Exit Scan because Alpaca advanced-order support is not used for this fractional quantity.'
                )

            return jsonify({
                'success': True,
                'action': 'ORDER_SUBMITTED',
                'symbol': symbol,
                'mode': mode_label,
                'orderId': order_id,
                'orderStatus': order_status,
                'order': order_data,
                'orderData': order_data,
                'submittedOrder': order_data,
                'orderType': 'limit',
                'orderClass': order_class,
                'protectionMode': protection_mode,
                'limitPrice': limit_price,
                'submittedShares': shares,
                'submittedNotional': preflight.get('notional'),
                'submittedRiskDollars': preflight.get('riskDollars'),
                'accountBuyingPower': round(buying_power, 2),
                'cashFundedBuyingPower': round(spendable_buying_power, 2),
                'marginUsed': bool(plan_snapshot.get('allowMargin', False)),
                'marketableLimit': preflight.get('marketable'),
                'preflight': preflight,
                'marketClock': market_clock,
                'quoteAgeSeconds': round(quote_age_seconds, 1) if quote_age_seconds is not None else None,
                'message': f'{mode_label.capitalize()} limit order submitted for {shares:g} shares of {symbol}',
                'note': note,
            })
        else:
            broker_error = _alpaca_order_error(order_resp)
            error_text = broker_error['brokerMessage']
            print(f'[ENTRY EXECUTE] {symbol}: Alpaca API error {order_resp.status_code}: {error_text}')
            if broker_error['code'] == 'duplicate_client_order_id':
                existing_order, _lookup_error = _alpaca_lookup_order_by_client_id(
                    base_url, headers, client_order_id,
                )
                if existing_order:
                    return _idempotent_existing_order_response(existing_order)
                return jsonify({
                    'success': False, 'action': 'BLOCKED', 'symbol': symbol,
                    'code': 'duplicate_client_order_id',
                    'reason': 'client_order_id must be unique — use Retry to submit with a new ID',
                    'blockers': ['Duplicate client order ID. Retry with a new ID.']
                })
            if user and not suppress_discord:
                send_discord_notification(user['id'], 'error', {
                    'event_id': f'entry-execute-api-{symbol}-{int(time.time())}',
                    'step': 'Entry Plan Execute',
                    'status': f'api_error_{order_resp.status_code}',
                    'symbol': symbol,
                    'reason': error_text[:300],
                    'action': 'Check Alpaca account status, order parameters, and buying power.',
                })
            return jsonify({
                'success': False, 'action': 'BLOCKED', 'symbol': symbol,
                **broker_error,
                'reason': error_text,
                'message': error_text,
                'blockers': [error_text],
            })

    except Exception as e:
        print(f'[ENTRY EXECUTE] Exception: {e}')
        import traceback
        traceback.print_exc()
        return jsonify({
            'success': False, 'action': 'ERROR', 'symbol': data.get('symbol', '?') if data else '?',
            'reason': str(e), 'blockers': [str(e)[:200]]
        }), 500


# ============ AI Execution Order Endpoint ============

@app.route('/api/ai/execution/order', methods=['POST'])
def ai_execution_order():
    """Place an order via Alpaca for AI Execution candidates.
    Respects trading mode (paper/real) and automation mode (manual/semi-ai/full-ai).
    All config comes from per-user Supabase — never from .env or global fallback."""
    import requests as _req

    data = request.get_json() or {}
    suppress_discord = bool(data.get('suppressDiscord'))

    # ── 1. Auth check ──
    user = get_supabase_user()
    if not user:
        return jsonify({'success': False, 'status': 'auth_required', 'message': 'Authentication required. Please sign in.'})

    def _notify_ai_exec_block(status, message):
        if suppress_discord:
            return
        send_discord_notification(user['id'], 'error', {
            'event_id': f'ai-exec-{status}-{symbol or "unknown"}-{int(time.time())}',
            'step': 'AI Execution Order',
            'status': status,
            'symbol': symbol,
            'reason': str(message)[:300],
            'action': 'Review AI execution mode, risk controls, and order inputs.',
        })

    # ── 2. Validate required fields ──
    symbol = (data.get('symbol') or '').upper().strip()
    side = (data.get('side') or '').lower().strip()
    order_type = (data.get('type') or 'market').lower().strip()
    try:
        trading_mode = _operations_normalize_trading_mode(
            data.get('tradingMode') or 'paper'
        )
        automation_mode = _operations_normalize_automation_mode(
            data.get('automationMode') or 'manual'
        )
    except ValueError as exc:
        return jsonify({
            'success': False,
            'status': 'validation_error',
            'message': str(exc),
        }), 400
    confirmed = data.get('confirmed', False)
    qty = data.get('qty')
    notional = data.get('notional')
    limit_price = data.get('limit_price')
    stop_price = data.get('stop_price')
    trail_price = data.get('trail_price')
    trail_percent = data.get('trail_percent')
    time_in_force = data.get('time_in_force', 'day')
    client_order_id = data.get('client_order_id') or data.get('clientOrderId')
    order_class = str(data.get('order_class') or data.get('orderClass') or 'simple').lower().strip()
    take_profit = data.get('take_profit') if isinstance(data.get('take_profit'), dict) else {}
    stop_loss = data.get('stop_loss') if isinstance(data.get('stop_loss'), dict) else {}
    take_profit_price = data.get('take_profit_price') or take_profit.get('limit_price')
    protective_stop_price = data.get('protective_stop_price') or stop_loss.get('stop_price')
    execution_source = str(data.get('executionSource') or '')

    if not symbol:
        _notify_ai_exec_block('risk_blocked', 'Symbol is required.')
        return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'Symbol is required.'})
    if side not in ('buy', 'sell'):
        _notify_ai_exec_block('risk_blocked', 'Side must be buy or sell.')
        return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'Side must be "buy" or "sell".'})
    if trading_mode == 'real' and side == 'buy':
        aal_error = _require_aal2(user, allow_headless_live_authority=True)
        if aal_error:
            return aal_error
        return jsonify({
            'success': False,
            'status': 'entry_plan_required',
            'code': 'entry_plan_required',
            'reason': 'entry_plan_required',
            'message': 'Real BUY orders must pass the server-side Entry Plan preflight.',
        }), 409
    valid_types = ('market', 'limit', 'stop', 'stop_limit', 'trailing_stop')
    if order_type not in valid_types:
        return jsonify({'success': False, 'status': 'risk_blocked', 'message': f'Type must be one of: {", ".join(valid_types)}.'})
    if (not qty or qty <= 0) and (not notional or notional <= 0):
        return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'qty or notional must be > 0.'})
    if order_class not in ('simple', 'oco'):
        return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'order_class must be simple or oco.'})
    if order_type == 'limit' and order_class != 'oco' and (not limit_price or limit_price <= 0):
        return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'Limit orders require limit_price > 0.'})
    if order_type == 'stop' and (not stop_price or stop_price <= 0):
        return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'Stop orders require stop_price > 0.'})
    if order_type == 'stop_limit':
        if not limit_price or limit_price <= 0:
            return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'Stop-limit orders require limit_price > 0.'})
        if not stop_price or stop_price <= 0:
            return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'Stop-limit orders require stop_price > 0.'})
    if order_type == 'trailing_stop':
        if (not trail_price or trail_price <= 0) and (not trail_percent or trail_percent <= 0):
            return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'Trailing stop orders require trail_price or trail_percent > 0.'})
    if order_class == 'oco':
        try:
            _oco_qty = float(qty or 0)
            _oco_tp = float(take_profit_price or 0)
            _oco_stop = float(protective_stop_price or 0)
        except (TypeError, ValueError):
            _oco_qty = _oco_tp = _oco_stop = 0
        if side != 'sell' or order_type != 'limit':
            return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'OCO protection requires a sell limit order.'})
        if _oco_qty < 1 or not float(_oco_qty).is_integer():
            return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'OCO protection requires a whole-share quantity.'})
        if _oco_tp <= 0 or _oco_stop <= 0 or _oco_stop >= _oco_tp:
            return jsonify({'success': False, 'status': 'risk_blocked', 'message': 'OCO requires a valid target above its protective stop.'})

    # ── 3. Automation mode gates ──
    if automation_mode == 'manual':
        _notify_ai_exec_block('risk_blocked', 'Manual mode - review only. No orders will be placed.')
        return jsonify({'success': False, 'status': 'risk_blocked',
                        'message': 'Manual mode — review only. No orders will be placed.'})
    if side == 'buy':
        safety_block = _operations_buy_submission_block(user['id'], trading_mode)
        if safety_block:
            _notify_ai_exec_block('safety_locked', safety_block['message'])
            return jsonify({
                'success': False,
                'status': 'safety_locked',
                **safety_block,
            }), 423
    order_preview = {
        'symbol': symbol, 'side': side, 'qty': qty, 'notional': notional,
        'type': order_type, 'limit_price': limit_price, 'stop_price': stop_price,
        'trail_price': trail_price, 'trail_percent': trail_percent,
        'time_in_force': time_in_force
    }
    if automation_mode == 'semi-ai' and not confirmed:
        return jsonify({'success': False, 'status': 'confirmation_required',
                        'message': 'Semi-AI mode requires confirmation before placing order.',
                        'orderPreview': order_preview})
    if automation_mode == 'full-ai' and trading_mode == 'real' and not confirmed:
        return jsonify({'success': False, 'status': 'confirmation_required',
                        'message': 'Real trading in Full-AI mode requires explicit confirmation.',
                        'orderPreview': order_preview})
    if automation_mode == 'full-ai' and trading_mode == 'real':
        automation_config = _pa_get_config(user['id']) or {}
        if automation_config.get('live_auto_trading_enabled') is not True:
            _notify_ai_exec_block('live_auto_not_enabled', 'Live background auto trading is not explicitly enabled.')
            return jsonify({
                'success': False,
                'status': 'risk_blocked',
                'code': 'live_auto_not_enabled',
                'message': 'Enable Live Auto Trading before unattended real orders.',
                'executionSource': execution_source,
            })
    if automation_mode == 'full-ai':
        automation_config = _pa_get_config(user['id']) or {}
        if str(automation_config.get('mode') or 'hybrid').lower() != 'ai':
            _notify_ai_exec_block(
                'full_ai_required',
                'Saved Market Auto Run mode is not Full AI.',
            )
            return jsonify({
                'success': False,
                'status': 'risk_blocked',
                'code': 'full_ai_required',
                'message': 'Automatic broker orders require saved Full AI mode.',
                'executionSource': execution_source,
            }), 403

    # ── 4. Resolve Alpaca config (strict user-only) ──
    alpaca_mode = 'paper' if trading_mode == 'paper' else 'live'
    alpaca_cfg, cfg_status = resolve_alpaca_config_strict_user(alpaca_mode)

    if cfg_status == 'auth_required':
        return jsonify({'success': False, 'status': 'auth_required', 'message': 'Session expired. Please sign in again.'})
    if cfg_status == 'config_required':
        mode_label = 'Paper Trading' if alpaca_mode == 'paper' else 'Live Trading'
        _notify_ai_exec_block('config_required', f'{mode_label} API keys not configured.')
        return jsonify({'success': False, 'status': 'config_required',
                        'message': f'{mode_label} API keys not configured. Please go to Settings > Configuration to set up your Alpaca keys.'})

    api_key = alpaca_cfg.get('api_key', '')
    api_secret = alpaca_cfg.get('api_secret', '')
    base_url = alpaca_cfg.get('base_url', 'https://paper-api.alpaca.markets' if alpaca_mode == 'paper' else 'https://api.alpaca.markets')

    # Double-check key validity
    key_bad, key_reason = _is_invalid_key(api_key)
    if key_bad:
        return jsonify({'success': False, 'status': 'config_required',
                        'message': f'API key is invalid ({key_reason}). Please re-configure in Settings.'})
    secret_bad, secret_reason = _is_invalid_key(api_secret)
    if secret_bad:
        return jsonify({'success': False, 'status': 'config_required',
                        'message': f'API secret is invalid ({secret_reason}). Please re-configure in Settings.'})

    # ── 5. Build and submit order to Alpaca ──
    headers = {
        'APCA-API-KEY-ID': api_key,
        'APCA-API-SECRET-KEY': api_secret,
        'Content-Type': 'application/json'
    }

    # Automatic exits must be reconciled against the broker immediately before
    # submission. This prevents stale position quantities, duplicate sell
    # orders, or an already-filled OCO leg from turning into an oversell.
    if side == 'sell':
        if not qty or float(qty or 0) <= 0:
            _notify_ai_exec_block('risk_blocked', 'Sell execution requires an explicit share quantity.')
            return jsonify({
                'success': False,
                'status': 'risk_blocked',
                'code': 'sell_quantity_required',
                'message': 'Sell execution requires an explicit share quantity.',
            })
        try:
            position_response = _req.get(
                f'{base_url}/v2/positions/{symbol}',
                headers=headers,
                timeout=10,
            )
            if position_response.status_code != 200:
                message = 'No verified open position is available for this sell order.'
                _notify_ai_exec_block('risk_blocked', message)
                return jsonify({
                    'success': False,
                    'status': 'risk_blocked',
                    'code': 'position_unavailable',
                    'message': message,
                })
            position_payload = position_response.json() or {}
            available_qty = abs(float(position_payload.get('qty') or 0))
            requested_qty = float(qty or 0)
            if requested_qty > available_qty + 1e-6:
                message = 'Sell quantity %.4f exceeds verified position quantity %.4f.' % (
                    requested_qty,
                    available_qty,
                )
                _notify_ai_exec_block('risk_blocked', message)
                return jsonify({
                    'success': False,
                    'status': 'risk_blocked',
                    'code': 'sell_quantity_exceeds_position',
                    'message': message,
                    'availableQty': available_qty,
                    'requestedQty': requested_qty,
                })

            open_order_response = _req.get(
                f'{base_url}/v2/orders',
                headers=headers,
                params={'status': 'open', 'symbols': symbol, 'nested': 'true', 'limit': 100},
                timeout=10,
            )
            if open_order_response.status_code != 200:
                message = 'Open sell orders could not be verified before submission.'
                _notify_ai_exec_block('risk_blocked', message)
                return jsonify({
                    'success': False,
                    'status': 'risk_blocked',
                    'code': 'open_orders_unavailable',
                    'message': message,
                })
            open_sell_orders = [
                order for order in _pa_flatten_alpaca_order_tree(open_order_response.json() or [])
                if str(order.get('symbol') or '').upper() == symbol
                and str(order.get('side') or '').lower() == 'sell'
            ]
            if open_sell_orders:
                message = 'An open sell/protection order already exists for %s.' % symbol
                _notify_ai_exec_block('risk_blocked', message)
                return jsonify({
                    'success': False,
                    'status': 'risk_blocked',
                    'code': 'open_sell_order_exists',
                    'message': message,
                    'openOrderIds': [order.get('id') for order in open_sell_orders if order.get('id')],
                })
        except Exception as sell_preflight_error:
            message = 'Sell preflight verification failed: %s' % str(sell_preflight_error)[:160]
            _notify_ai_exec_block('risk_blocked', message)
            return jsonify({
                'success': False,
                'status': 'risk_blocked',
                'code': 'sell_preflight_failed',
                'message': message,
            })

    order_payload = {
        'symbol': symbol,
        'side': side,
        'type': order_type,
        'time_in_force': time_in_force,
    }
    if qty and qty > 0:
        order_payload['qty'] = str(qty)
    elif notional and notional > 0:
        order_payload['notional'] = str(round(notional, 2))
    if order_type in ('limit', 'stop_limit') and limit_price and order_class != 'oco':
        order_payload['limit_price'] = str(limit_price)
    if order_type in ('stop', 'stop_limit') and stop_price:
        order_payload['stop_price'] = str(stop_price)
    if order_type == 'trailing_stop':
        if trail_price and trail_price > 0:
            order_payload['trail_price'] = str(trail_price)
        elif trail_percent and trail_percent > 0:
            order_payload['trail_percent'] = str(trail_percent)
    if side == 'buy':
        order_payload['client_order_id'] = _operations_managed_buy_client_order_id(
            user['id'], symbol, client_order_id,
        )
    elif client_order_id:
        order_payload['client_order_id'] = str(client_order_id)[:48]
    if order_class == 'oco':
        order_payload.update({
            'order_class': 'oco',
            'take_profit': {'limit_price': str(round(float(take_profit_price), 4))},
            'stop_loss': {'stop_price': str(round(float(protective_stop_price), 4))},
        })

    mode_label = 'paper' if alpaca_mode == 'paper' else 'real'
    print(f'[AI EXECUTION] {symbol} {side} {order_type} mode={mode_label} auto={automation_mode} user={user["id"][:8]}...')

    try:
        if side == 'buy':
            safety_block = _operations_buy_submission_block(user['id'], trading_mode)
            if safety_block:
                _notify_ai_exec_block('safety_locked', safety_block['message'])
                return jsonify({
                    'success': False,
                    'status': 'safety_locked',
                    **safety_block,
                }), 423
        resp = _req.post(f'{base_url}/v2/orders', headers=headers, json=order_payload, timeout=30)
        if resp.status_code in (200, 201):
            order_data = resp.json()
            print(f'[AI EXECUTION] {symbol}: ORDER SUBMITTED id={order_data.get("id")} status={order_data.get("status")}')
            _record_order_lifecycle(
                user['id'],
                order_data.get('id') or order_data.get('client_order_id'),
                'ai_execution_submitted',
                order_data.get('status') or 'submitted',
                payload={
                    'mode': mode_label, 'side': side, 'symbol': symbol,
                    'type': order_type, 'orderClass': order_class,
                    'automationMode': automation_mode,
                    'clientOrderId': order_data.get('client_order_id'),
                },
            )
            if not suppress_discord:
                send_discord_notification(user['id'], 'order', {
                    'event_id': order_data.get('id') or order_data.get('client_order_id') or f'ai-exec-order-{symbol}-{int(time.time())}',
                    'mode': mode_label,
                    'side': side,
                    'symbol': symbol,
                    'qty': qty,
                    'notional': notional,
                    'orderType': order_type,
                    'orderClass': order_class,
                    'limitPrice': limit_price,
                    'status': order_data.get('status') or 'submitted',
                    'orderId': order_data.get('id'),
                    'reason': f'AI execution {automation_mode} submitted order.',
                })
            return jsonify({
                'success': True, 'status': 'submitted',
                'message': f'{mode_label.capitalize()} {order_type} order submitted for {symbol}',
                'order': order_data,
                'modeUsed': mode_label,
                'endpointUsed': f'{base_url}/v2/orders'
            })
        else:
            broker_error = _alpaca_order_error(resp)
            error_text = broker_error['brokerMessage']
            print(f'[AI EXECUTION] {symbol}: Alpaca error {resp.status_code}: {error_text}')
            _notify_ai_exec_block(f'api_error_{resp.status_code}', error_text)
            return jsonify({
                'success': False, 'status': 'api_error',
                **broker_error,
                'message': error_text,
                'modeUsed': mode_label,
            })
    except Exception as e:
        print(f'[AI EXECUTION] {symbol}: Exception {e}')
        _notify_ai_exec_block('api_error', str(e))
        return jsonify({
            'success': False, 'status': 'api_error',
            'message': f'Order submission failed: {str(e)[:200]}',
            'modeUsed': mode_label
        }), 500


# ============ AI Agent Watchlist Endpoints ============

def _find_watchlist_item(symbol, user_id):
    """Find watchlist item by symbol (case-insensitive). Returns (index, item) or (None, None)."""
    sym_upper = symbol.upper().strip()
    for i, item in enumerate(_watchlist_store):
        if item.get('ownerId') != user_id:
            continue
        if item.get('symbol', '').upper().strip() == sym_upper:
            return i, item
    return None, None


@app.route('/api/ai-agent/watchlist', methods=['GET'])
def ai_agent_watchlist_list():
    """List all AI Agent watchlist items."""
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    items = [item for item in _watchlist_store if item.get('ownerId') == user['id']]
    return jsonify({'success': True, 'items': items, 'count': len(items)})


@app.route('/api/ai-agent/watchlist', methods=['POST'])
def ai_agent_watchlist_add():
    """Add or update an item in the AI Agent watchlist."""
    import time as _time
    from datetime import datetime as _dt

    try:
        user = require_auth()
        if not user:
            return jsonify({'success': False, 'message': 'Authentication required'}), 401
        data = request.get_json()
        if not data:
            return jsonify({'success': False, 'message': 'No data provided'}), 400

        symbol = data.get('symbol', '').upper().strip()
        if not symbol:
            return jsonify({'success': False, 'message': 'Symbol required'}), 400

        existing_idx, existing_item = _find_watchlist_item(symbol, user['id'])

        item = {
            'id': data.get('id', str(_uuid.uuid4())[:8]),
            'ownerId': user['id'],
            'symbol': symbol,
            'setupType': data.get('setupType', ''),
            'aiDecision': data.get('aiDecision', 'WATCH'),
            'confidence': data.get('confidence', 0),
            'entryZoneLow': data.get('entryZoneLow'),
            'entryZoneHigh': data.get('entryZoneHigh'),
            'trigger': data.get('trigger', ''),
            'stopLoss': data.get('stopLoss'),
            'takeProfit1': data.get('takeProfit1'),
            'takeProfit2': data.get('takeProfit2'),
            'riskReward': data.get('riskReward'),
            'shares': data.get('shares'),
            'finalAction': data.get('finalAction', 'WAIT_FOR_ENTRY'),
            'riskGateStatus': data.get('riskGateStatus', ''),
            'dataQuality': data.get('dataQuality', ''),
            'nextStep': data.get('nextStep', ''),
            'decisionReason': data.get('decisionReason', ''),
            'riskComment': data.get('riskComment', ''),
            'invalidationComment': data.get('invalidationComment', ''),
            'source': data.get('source', 'Entry Plan'),
            'selectedBy': data.get('selectedBy', ''),
            'createdAt': data.get('createdAt', _dt.utcnow().isoformat() + 'Z'),
            'updatedAt': _dt.utcnow().isoformat() + 'Z',
            'status': data.get('status', 'ACTIVE')
        }

        if existing_item is not None:
            # Update existing — preserve original id and createdAt
            item['id'] = existing_item.get('id', item['id'])
            item['createdAt'] = existing_item.get('createdAt', item['createdAt'])
            _watchlist_store[existing_idx] = item
            print(f'[WATCHLIST] Updated {symbol}')
            return jsonify({
                'success': True, 'action': 'UPDATED', 'item': item,
                'message': f'{symbol} updated in watchlist'
            })

        _watchlist_store.append(item)
        print(f'[WATCHLIST] Added {symbol} (total: {len(_watchlist_store)})')
        return jsonify({
            'success': True, 'action': 'ADDED', 'item': item,
            'message': f'{symbol} added to watchlist'
        })

    except Exception as e:
        print(f'[WATCHLIST] Error adding: {e}')
        return jsonify({'success': False, 'message': str(e)}), 500


@app.route('/api/ai-agent/watchlist/<item_id>', methods=['DELETE'])
def ai_agent_watchlist_remove(item_id):
    """Remove an item from the AI Agent watchlist."""
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    for i, item in enumerate(_watchlist_store):
        if item.get('id') == item_id and item.get('ownerId') == user['id']:
            removed = _watchlist_store.pop(i)
            print(f'[WATCHLIST] Removed {removed.get("symbol")} id={item_id}')
            return jsonify({'success': True, 'message': f'{removed.get("symbol")} removed from watchlist'})
    return jsonify({'success': False, 'message': 'Item not found'}), 404


@app.route('/api/ai-agent/watchlist/<item_id>', methods=['PATCH'])
def ai_agent_watchlist_update(item_id):
    """Update watchlist item status or other fields."""
    import time as _time
    from datetime import datetime as _dt

    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401

    for i, item in enumerate(_watchlist_store):
        if item.get('id') == item_id and item.get('ownerId') == user['id']:
            data = request.get_json() or {}
            if 'status' in data:
                _watchlist_store[i]['status'] = data['status']
            if 'nextStep' in data:
                _watchlist_store[i]['nextStep'] = data['nextStep']
            _watchlist_store[i]['updatedAt'] = _dt.utcnow().isoformat() + 'Z'
            print(f'[WATCHLIST] Updated {_watchlist_store[i].get("symbol")} id={item_id}')
            return jsonify({'success': True, 'item': _watchlist_store[i], 'message': 'Updated'})
    return jsonify({'success': False, 'message': 'Item not found'}), 404


