@app.route('/api/operations/artifacts', methods=['GET', 'PUT', 'DELETE'])
def operations_artifacts():
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    try:
        if request.method == 'GET':
            artifact_type = request.args.get('artifactType')
            artifact_key = request.args.get('artifactKey')
            if artifact_key:
                row = operations_store.get_artifact(uid, artifact_type, artifact_key)
                return jsonify({
                    'success': True,
                    'artifact': _operations_artifact_public(row) if row else None,
                    'storage': operations_store.backend,
                })
            rows = operations_store.list_artifacts(
                uid, artifact_type=artifact_type, limit=_operations_limit(100),
            )
            return jsonify({
                'success': True,
                'artifacts': [_operations_artifact_public(row) for row in rows],
                'storage': operations_store.backend,
            })
        data = request.get_json(silent=True) or {}
        artifact_type = data.get('artifactType') or request.args.get('artifactType')
        artifact_key = data.get('artifactKey') or request.args.get('artifactKey')
        if request.method == 'PUT':
            row = operations_store.put_artifact(
                uid, artifact_type, artifact_key,
                payload=data.get('payload') or {},
                idempotency_key=_operations_request_key(data, 'artifact'),
                expected_version=data.get('expectedVersion'),
            )
            _record_operations_audit(
                uid, 'artifact_saved', _operations_deterministic_key(
                    'audit-artifact', uid, artifact_type, artifact_key, row.get('version'),
                ),
                actor='user', source='operations_artifacts', resource_type=artifact_type,
                resource_id=artifact_key,
                payload={'version': row.get('version')},
            )
            return jsonify({
                'success': True,
                'artifact': _operations_artifact_public(row),
                'storage': operations_store.backend,
            })
        deleted = operations_store.delete_artifact(
            uid, artifact_type, artifact_key,
            expected_version=data.get('expectedVersion'),
        )
        if deleted:
            key = _operations_request_key(data, 'artifact-delete')
            _record_operations_audit(
                uid, 'artifact_deleted', 'audit:%s' % key,
                actor='user', source='operations_artifacts', resource_type=artifact_type,
                resource_id=artifact_key,
            )
        return jsonify({'success': True, 'deleted': deleted, 'storage': operations_store.backend})
    except Exception as exc:
        return _operations_error_response(exc)


@app.route('/api/ai-agent/exit-scan', methods=['POST'])
def pipeline_exit_scan():
    """Run the same exit engine used by the unattended Position Guard."""
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    data = request.get_json(silent=True) or {}
    pipeline_mode = str(data.get('pipelineMode') or data.get('mode') or 'hybrid').lower()
    if pipeline_mode not in {'manual', 'hybrid', 'ai'}:
        return jsonify({
            'success': False,
            'status': 'validation_error',
            'message': 'pipeline mode must be manual, hybrid, or ai',
        }), 400
    try:
        trade_mode = _operations_normalize_trading_mode(data.get('tradeMode') or 'paper')
    except ValueError as exc:
        return jsonify({
            'success': False,
            'status': 'validation_error',
            'message': str(exc),
        }), 400
    auto_submit = bool(data.get('autoSubmit')) and pipeline_mode == 'ai'
    if not _pa_try_reserve_user_run(uid, 'manual_exit_scan'):
        return jsonify({
            'success': False,
            'status': 'already_running',
            'message': 'A pipeline or position-protection run is already active. Retry shortly.',
        }), 409
    try:
        summary = _pa_exit_scan_headless(
            uid,
            data.get('entryPlans') if isinstance(data.get('entryPlans'), list) else [],
            pipeline_mode,
            dry_run=not auto_submit,
            risk_profile=data.get('riskProfile') or 'medium',
            time_horizon=data.get('timeHorizon') or 'mid',
            trade_mode=trade_mode,
            run_id='manual-exit-%d' % int(time.time()),
            ai_review=data.get('aiReview', True) is not False,
            suppress_discord=bool(data.get('suppressDiscord', False)),
        )
        status_code = 200 if not summary.get('error') else 502
        return jsonify({'success': not bool(summary.get('error')), **summary}), status_code
    finally:
        _pa_release_user_run(uid)


@app.route('/api/ai-agent/pipeline-auto/status', methods=['GET'])
def pipeline_auto_status():
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    config = _pa_get_config(uid)
    enabled = config.get('enabled', False) if config else False
    interval_minutes = config.get('interval_minutes', 0) if config else 0
    mode = config.get('mode', 'hybrid') if config else 'hybrid'

    scheduler_health = _pa_scheduler_health_snapshot()
    with _PA_SCHEDULER_LAST_HEARTBEAT_LOCK:
        hb = _PA_SCHEDULER_LAST_HEARTBEAT
    scheduler_running = scheduler_health['running']
    _status_trade_mode = config.get('trade_mode') or config.get('tradeMode') or 'paper'
    is_open, mkt_status, mkt_source, next_open, next_close, market_stage = _pa_check_market_open(uid, _status_trade_mode)

    with _PA_PER_USER_LAST_CHECK_LOCK:
        last_check = _PA_PER_USER_LAST_CHECK.get(uid, {})
    last_decision = last_check.get('decision', config.get('last_decision', ''))
    last_run_at = config.get('last_run_at', '')
    last_summary = config.get('last_summary', {})
    last_error = config.get('last_error', '')
    with _PA_RUNNING_USERS_LOCK:
        is_running = uid in _PA_RUNNING_USERS
    discord_cfg = get_discord_config(uid)
    discord_enabled = bool(discord_cfg.get('enabled') and discord_cfg.get('webhookUrl'))
    with _PA_POSITION_GUARD_LOCK:
        position_guard_state = dict(_PA_POSITION_GUARD_STATE.get(uid, {}))
    position_guard_enabled = bool(
        config
        or _pa_managed_records_for_user(uid, _status_trade_mode)
        or get_user_config(uid, 'alpaca')
    )
    if position_guard_state.get('running'):
        is_running = False

    # Use the completed timestamp for display/fallback scheduling. The scheduler's
    # persisted next_run_at remains authoritative because intervals start after a
    # full cycle finishes, not when the cycle begins.
    next_from_last_et = None
    last_auto_run_display = ''
    last_completed_at = (last_summary or {}).get('finishedAt') or last_run_at
    if last_completed_at:
        try:
            _l = dateutil.parser.isoparse(last_completed_at)
            _l_et = _pa_as_et(_l)
            last_auto_run_display = _l_et.strftime('%H:%M')
            if enabled and interval_minutes > 0:
                next_from_last_et = _l_et + timedelta(minutes=interval_minutes)
        except:
            pass

    # ── Phase 2: scheduler next_run_at (for backend scheduler loop) ──
    next_run_at = ''
    seconds_until_next = 0
    config_next_run = config.get('next_run_at', '') if config else ''
    authoritative_next_et = None
    if enabled and interval_minutes > 0:
        if not is_open:
            # When market is closed, ALWAYS point to next market open, never use last_run+interval
            next_run_at = next_open if next_open else 'Waiting for next market open'
        elif config_next_run and config_next_run not in ('', 'now', 'Waiting for next market open'):
            try:
                parsed = dateutil.parser.isoparse(config_next_run)
                now_et = _pa_now_et()
                parsed_et = _pa_as_et(parsed)
                authoritative_next_et = parsed_et
                next_run_at = parsed_et.isoformat()
                seconds_until_next = max(0, (parsed_et - now_et).total_seconds())
            except Exception:
                if next_from_last_et:
                    now_et = _pa_now_et()
                    next_run_at = next_from_last_et.isoformat()
                    seconds_until_next = max(0, (next_from_last_et - now_et).total_seconds())
                else:
                    next_run_at = 'now'
        elif next_from_last_et:
            now_et = _pa_now_et()
            next_run_at = next_from_last_et.isoformat()
            seconds_until_next = max(0, (next_from_last_et - now_et).total_seconds())
        else:
            next_run_at = 'now'

    # ── Phase 3: display fields ──
    next_auto_run_at = ''
    next_auto_run_display = ''
    stopped_for_today = False
    blocked_for_day = False
    next_run_basis = ''
    next_market_open_display = ''
    next_market_open_at = ''

    # Helper to format next market open with date from next_open ISO string
    def _fmt_next_open(no_val):
        if not no_val:
            return '', ''
        try:
            _no = dateutil.parser.isoparse(no_val) if isinstance(no_val, str) else no_val
            if _no is not None and hasattr(_no, 'strftime'):
                _no_et = _pa_as_et(_no)
                return _no_et.isoformat(), _no_et.strftime('%a %m-%d %H:%M ET')
        except Exception:
            pass
        return '', ''

    if is_open:
        # Market is open — use interval-based scheduling
        display_next_et = authoritative_next_et or next_from_last_et
        if display_next_et:
            next_auto_run_at = display_next_et.isoformat()
            next_auto_run_display = display_next_et.strftime('%H:%M')
            # 16:00 ET cut-off: if computed next >= today 16:00, stop for today
            _close_et = display_next_et.replace(hour=16, minute=0, second=0, microsecond=0)
            if display_next_et >= _close_et:
                stopped_for_today = True
                next_run_basis = 'market_closed_after_1600'
                next_market_open_at, next_market_open_display = _fmt_next_open(next_open)
            else:
                next_run_basis = 'persisted_next_run_at' if authoritative_next_et else 'last_completed_at_plus_interval'
        elif enabled and interval_minutes > 0:
            next_auto_run_display = 'Ready'
            next_run_basis = 'first_run_today'
    elif market_stage == 'premarket':
        # Trading day, before 09:30 — next run is today at open
        stopped_for_today = False
        blocked_for_day = False
        next_run_basis = 'premarket'
        now_et = _pa_now_et()
        today_open = now_et.replace(hour=9, minute=30, second=0, microsecond=0)
        next_auto_run_at = today_open.isoformat()
        next_auto_run_display = today_open.strftime('%H:%M')
        next_market_open_at = today_open.isoformat()
        next_market_open_display = today_open.strftime('%a %m-%d %H:%M ET')
    elif market_stage == 'after_hours':
        # Market closed for the day — next is next trading day
        stopped_for_today = True
        blocked_for_day = False
        next_run_basis = 'after_hours'
        next_market_open_at, next_market_open_display = _fmt_next_open(next_open)
    elif market_stage in ('weekend', 'holiday'):
        # No market at all today
        stopped_for_today = True
        blocked_for_day = True
        next_run_basis = market_stage
        next_market_open_at, next_market_open_display = _fmt_next_open(next_open)
    else:
        # Fallback: unknown market stage
        if enabled and interval_minutes > 0:
            stopped_for_today = True
            blocked_for_day = True
            next_market_open_at, next_market_open_display = _fmt_next_open(next_open)

    # Fallback: compute next trading day if next_open didn't yield a display
    if (stopped_for_today or blocked_for_day) and not next_market_open_display:
        now_et = _pa_now_et()
        next_trading = _pa_get_next_trading_day(now_et)
        if next_trading:
            next_market_open_at = next_trading.isoformat()
            next_market_open_display = _pa_format_next_open_display(next_trading)

    # Progress / status labels
    progress_state = 'off'
    progress_percent = 0
    progress_label = 'Auto pipeline off'
    auto_status = 'Off'
    circuit_breaker_open = _pa_is_circuit_breaker_open(config)

    if enabled:
        if not scheduler_running:
            progress_state = 'offline'
            progress_label = 'Scheduler offline — auto pipeline will not run'
            auto_status = 'Error'
        elif not is_open:
            if market_stage == 'premarket':
                progress_state = 'premarket'
                progress_label = 'Premarket — waiting for open at 09:30 ET'
                auto_status = 'Premarket'
            elif market_stage == 'holiday':
                progress_state = 'market_closed'
                progress_label = 'Holiday closed — auto pipeline will not run today'
                auto_status = 'Holiday Closed'
            elif market_stage == 'weekend':
                progress_state = 'market_closed'
                progress_label = 'Weekend closed — auto pipeline will not run today'
                auto_status = 'Weekend Closed'
            else:
                progress_state = 'market_closed'
                progress_label = 'Market closed — waiting for next open'
                auto_status = 'Market Closed'
        elif circuit_breaker_open:
            progress_state = 'circuit_open'
            progress_label = 'Circuit breaker open — research scans are temporarily paused'
            auto_status = 'Circuit Open'
        elif is_running or last_decision == 'started_pipeline':
            progress_state = 'running'
            progress_label = 'Running AI pipeline...'
            progress_percent = int((_pa_get_active_run(uid) or {}).get('progressPct') or 0)
            auto_status = 'Running'
        else:
            progress_state = 'armed'
            auto_status = 'Armed'
            if interval_minutes > 0 and seconds_until_next > 0:
                progress_percent = min(100, int((interval_minutes * 60 - seconds_until_next) / (interval_minutes * 60) * 100))
                mins = int(seconds_until_next // 60)
                secs = int(seconds_until_next % 60)
                progress_label = 'Next auto pipeline in %02d:%02d' % (mins, secs)
            else:
                progress_label = 'Ready to run'

    market_status_label = mkt_status
    if mkt_status == 'open':
        market_status_label = 'Open'
    elif mkt_status == 'closed':
        market_status_label = 'Closed'
    elif mkt_status == 'holiday':
        market_status_label = 'Holiday Closed'
    if mkt_source == 'fallback_basic_hours':
        market_status_label += ' (Fallback)'

    # ── Phase 5: auto-run display fields ──
    _now_et = _pa_now_et()
    _run_count_today = 0
    if config and str(config.get('run_count_date_et') or '') == _now_et.strftime('%Y-%m-%d'):
        try:
            _run_count_today = max(0, int(config.get('run_count_today') or 0))
        except (TypeError, ValueError):
            _run_count_today = 0
    active_run = _pa_get_active_run(uid)
    # Stale detection: if activeRun hasn't been updated in 15+ minutes while "running", mark as stalled.
    # The institutional 1500-symbol scan can spend several minutes on provider
    # batches and AI review, so a short generic request threshold is misleading.
    STALE_THRESHOLD = 900  # 15 minutes
    stale_detected = False
    if active_run and active_run.get('status') == 'running' and active_run.get('updatedAt'):
        try:
            _updated = dateutil.parser.isoparse(active_run['updatedAt'])
            _now_utc = datetime.now(timezone.utc)
            _age = (_now_utc - _updated.astimezone(timezone.utc)).total_seconds() if _updated.tzinfo else (_now_utc.replace(tzinfo=None) - _updated).total_seconds()
            if _age > STALE_THRESHOLD:
                stale_detected = True
                _pa_log_error('[PipelineAuto] stale run detected user=%s age=%.0fs step=%s (threshold=%ds)' % (uid[:8], _age, active_run.get('currentStep', '?'), STALE_THRESHOLD))
                _pa_update_active_run(
                    uid,
                    status='interrupted',
                    message='No backend progress heartbeat for 15 minutes',
                    lastError='stale_run_interrupted',
                    finishedAt=_pa_utc_iso(),
                )
                active_run = _pa_get_active_run(uid)
        except Exception:
            pass
    is_auto_run_running = is_running and not stale_detected
    current_auto_step = active_run.get('currentStep', '') if active_run else ''
    current_auto_progress_pct = active_run.get('progressPct', 0) if active_run else 0
    if stale_detected:
        current_auto_step = active_run.get('currentStep', 'stale') if active_run else 'stale'
        current_auto_progress_pct = active_run.get('progressPct', 0) if active_run else 0
    last_auto_summary = {}
    if last_summary:
        last_auto_summary = {
            'trigger': last_summary.get('trigger', ''),
            'completedAt': last_summary.get('finishedAt', ''),
            'durationSeconds': last_summary.get('durationSeconds', 0),
            'scanned': last_summary.get('scanned', 0),
            'aiSuccess': last_summary.get('aiSuccess', 0),
            'fineScanCount': last_summary.get('fine_count', 0),
            'validationCount': last_summary.get('validation_count', 0),
            'admissionCount': last_summary.get('admission_count', 0),
            'entryPlanCount': last_summary.get('entry_plan_count', 0),
            'ordersSubmitted': last_summary.get('orders_submitted', 0),
            'exitScanCount': last_summary.get('exit_scan_count', 0),
            'errors': last_summary.get('errors', 0),
        }

    resp = {
        'success': True,
        'enabled': enabled,
        'autoRunEnabledFromDb': enabled,
        'configUpdatedAt': config.get('updated_at', '') if config else '',
        'stopRequested': bool(config.get('stopRequested', False)) if config else False,
        'intervalMinutes': interval_minutes,
        'mode': mode,
        'schedulerRunning': scheduler_running,
        'schedulerLastHeartbeatAt': datetime.fromtimestamp(hb, timezone.utc).isoformat().replace('+00:00', 'Z') if hb > 0 else '',
        'schedulerLastCheckAt': last_check.get('time', ''),
        'schedulerLoopIntervalSeconds': 30,
        'schedulerHealth': scheduler_health,
        'marketOpen': is_open,
        'marketStatus': market_status_label,
        'marketStatusRaw': mkt_status,
        'marketStatusSource': mkt_source,
        'marketStage': market_stage,
        'nowEt': _pa_now_et().isoformat(),
        'todayDateEt': _pa_now_et().strftime('%Y-%m-%d'),
        'autoStatus': auto_status,
        'nextRunAt': next_run_at,
        'secondsUntilNextRun': seconds_until_next,
        'lastRunAt': last_run_at,
        'lastRunStartedAt': last_run_at,
        'isRunning': is_running,
        'lastDecision': last_decision,
        'lastRunTrigger': config.get('last_run_trigger', '') if config else '',
        'currentAutoRunId': config.get('current_auto_run_id', '') if config else '',
        'activeRun': active_run,
        'isAutoRunRunning': is_auto_run_running,
        'currentAutoStep': current_auto_step,
        'currentAutoProgressPct': current_auto_progress_pct,
        'staleDetected': stale_detected,
        'lastAutoError': active_run.get('lastError', '') if active_run else '',
        'lastAutoSummary': last_auto_summary,
        'lastAutoRunDisplay': last_auto_run_display,
        'nextAutoRunAt': next_auto_run_at,
        'nextAutoRunDisplay': next_auto_run_display,
        'stoppedForToday': stopped_for_today,
        'blockedForDay': blocked_for_day,
        'nextRunBasis': next_run_basis,
        'nextMarketOpenDisplay': next_market_open_display,
        'nextMarketOpenAt': next_market_open_at,
        'lastSummary': last_summary,
        'lastError': last_error,
        'consecutiveFailures': int(config.get('consecutive_failures') or 0) if config else 0,
        'circuitBreakerUntil': config.get('circuit_breaker_until', '') if config else '',
        'circuitBreakerOpen': circuit_breaker_open,
        'runCountToday': _run_count_today,
        # Backend headless capability: the same seven-stage pipeline runs without
        # a browser and includes admission, execution, and protected exit scans.
        'backendHeadlessCapable': True,
        'browserOpenRequiredForFullPipeline': False,
        'pipelineStages': [{'key': key, 'label': label} for key, label in _PA_PIPELINE_STAGES],
        'aiAuthority': _PA_AI_AUTHORITY,
        'positionGuard': {
            'enabled': position_guard_enabled,
            'independentFromMarketAutoRun': True,
            'intervalSeconds': _PA_POSITION_GUARD_INTERVAL_SECONDS,
            'lastDurableHeartbeatAt': config.get('position_guard_last_heartbeat_at', '') if config else '',
            **position_guard_state,
        },
        'discordEnabled': discord_enabled,
        'discordPolicy': {
            'tradeActivity': _discord_event_enabled(discord_cfg, 'order'),
            'riskAlerts': _discord_event_enabled(discord_cfg, 'risk_alert'),
            'cycleDigest': _discord_event_enabled(discord_cfg, 'cycle_digest'),
            'recommendations': _discord_event_enabled(discord_cfg, 'recommendation'),
            'quietMode': True,
        },
        'discordLastSentAt': _discord_last_sent_at.get(uid, ''),
        'riskProfile': config.get('risk_profile') or config.get('riskProfile') or 'medium',
        'timeHorizon': config.get('time_horizon') or config.get('timeHorizon') or 'mid',
        'tradeMode': config.get('trade_mode') or config.get('tradeMode') or 'paper',
        'liveAutoTradingEnabled': bool(config.get('live_auto_trading_enabled', False)),
        'orderAuthority': _pa_order_authority(config),
        'leverageEnabled': bool(config.get('leverage_enabled', False)),
        'strategyPolicy': _strategy_policy(
            config.get('risk_profile') or config.get('riskProfile') or 'medium',
            config.get('time_horizon') or config.get('timeHorizon') or 'mid',
            config.get('mode') or 'hybrid',
            config.get('leverage_enabled', False),
        ),
        'effectiveLimits': _strategy_policy(
            config.get('risk_profile') or config.get('riskProfile') or 'medium',
            config.get('time_horizon') or config.get('timeHorizon') or 'mid',
            config.get('mode') or 'hybrid',
            config.get('leverage_enabled', False),
        )['effectiveLimits'],
        'contextSource': _pa_resolve_auto_run_context(uid, config)['contextSource'],
        'lastBackendRunAt': last_run_at,
        'lastBackendRunStatus': 'success' if last_decision in ('pipeline_success', 'auto_run_now_success', 'manual_pipeline_success') else
                                'failed' if last_decision in ('pipeline_failed', 'auto_run_now_failed', 'manual_pipeline_failed') else
                                'blocked' if last_decision in ('blocked_real_order_submit',) else
                                'running' if is_running or last_decision == 'started_pipeline' else
                                '',
        'lastBackendRunReason': config.get('last_error', '') or
                                ('Backend scheduler runs the headless full pipeline.'
                                 if last_decision == 'started_pipeline' or last_decision == 'pipeline_success'
                                 else last_decision if last_decision else ''),
        'lastRunSource': config.get('last_run_source', ''),
        'marketWindow': {
            'timezone': 'America/New_York',
            'open': '09:30',
            'close': '16:00',
        },
        'progress': {
            'state': progress_state,
            'percent': progress_percent,
            'label': progress_label,
        },
    }
    return jsonify(resp)


@app.route('/api/ai-agent/pipeline-auto/claim-run', methods=['POST'])
def pipeline_auto_claim_run():
    """DEPRECATED: Auto-run no longer requires frontend claim.
    Returns success: false with a deprecation message.
    """
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    return jsonify({
        'success': False,
        'claimed': False,
        'message': 'Claim mechanism is deprecated. Auto-run is now fully headless.',
    })


@app.route('/api/ai-agent/pipeline/run', methods=['POST'])
def pipeline_run():
    """Shared entry point for manual and auto pipeline runs.
    Returns run_id immediately; frontend polls activeRun via status endpoint.
    """
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    data = request.get_json(silent=True) or {}
    mode = data.get('mode', 'hybrid')
    trigger = data.get('trigger', 'manual')
    interval = int(data.get('intervalMinutes') or 0)  # 0 for manual runs (no scheduling)
    risk_profile = data.get('riskProfile', 'medium')
    time_horizon = data.get('timeHorizon', 'mid')
    trade_mode = data.get('tradeMode', 'paper')
    leverage_enabled = data.get('leverageEnabled')
    if leverage_enabled is not None and not isinstance(leverage_enabled, bool):
        return jsonify({
            'success': False,
            'reason': 'invalid_leverage_preference',
            'message': 'leverageEnabled must be true or false.',
        }), 400
    run_id = 'pipeline-run-%d' % int(time.time())

    is_manual_req = (trigger == 'manual')
    if is_manual_req:
        _pa_log('[ManualPipeline] endpoint received trigger=%s mode=%s risk=%s horizon=%s tradeMode=%s runId=%s uid=%s' % (
            trigger, mode, risk_profile, time_horizon, trade_mode, run_id, uid[:8]))
    else:
        auto_config = _pa_get_config(uid) or {}
        if _pa_is_circuit_breaker_open(auto_config):
            return jsonify({
                'success': False,
                'status': 'circuit_open',
                'reason': 'circuit_breaker_open',
                'message': 'Automated research is paused by the circuit breaker. Position protection remains active.',
                'retryAt': auto_config.get('circuit_breaker_until', ''),
            }), 409

    if not _pa_try_reserve_user_run(uid, 'pipeline_endpoint'):
        if not _pa_user_run_is_reserved(uid):
            return _pa_pipeline_capacity_response()
        # Check if it's a background auto-run vs manual run
        active_run = _pa_get_active_run(uid)
        is_auto = active_run and active_run.get('trigger', '') in ('market_auto_run', 'headless_market_auto_run', 'toggle_on', 'auto_run_now')
        msg = 'Background auto-run is active. Please wait for it to complete or stop it first.' if is_auto else 'Pipeline already running'
        return jsonify({'success': False, 'message': msg, 'status': 'already_running'}), 409

    def _background_run():
        try:
            if is_manual_req:
                _pa_log('[ManualPipeline] background thread starting runId=%s' % run_id)
            config = _pa_get_config(uid) or {}
            config['current_auto_run_id'] = run_id
            _pa_execute_and_save(uid, config, interval, mode, trigger=trigger,
                                 risk_profile=risk_profile, time_horizon=time_horizon,
                                 trade_mode=trade_mode, run_id=run_id,
                                 leverage_enabled=leverage_enabled)
            if is_manual_req:
                _pa_log('[ManualPipeline] background thread completed runId=%s' % run_id)
        except Exception:
            import traceback
            _pa_log_error('[PipelineRun] background error: %s' % traceback.format_exc())

    threading.Thread(target=_background_run, daemon=True).start()
    return jsonify({'success': True, 'runId': run_id, 'message': 'Pipeline started'})


@app.route('/api/ai-agent/pipeline/result', methods=['GET'])
def pipeline_result():
    """Return the latest full pipeline result/debug dump for the current user."""
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    run_id = (request.args.get('runId') or '').strip()
    kind = (request.args.get('kind') or '').strip().lower()
    key = (uid, run_id) if run_id else (uid, '__last_manual__' if kind == 'manual' else '__last_auto__' if kind == 'auto' else '__last__')
    with _PA_LAST_PIPELINE_RESULTS_LOCK:
        _pa_prune_pipeline_results_locked()
        result = _PA_LAST_PIPELINE_RESULTS.get(key)
    if not result:
        filenames = []
        if kind == 'manual':
            filenames = ['debug_manual_pipeline_result.json']
        elif kind == 'auto':
            filenames = ['debug_auto_pipeline_result.json']
        else:
            filenames = ['debug_manual_pipeline_result.json', 'debug_auto_pipeline_result.json']
        for filename in filenames:
            try:
                path = os.path.join(os.path.dirname(os.path.abspath(__file__)), filename)
                if not os.path.exists(path):
                    continue
                with open(path, 'r', encoding='utf-8') as handle:
                    candidate = json.load(handle)
                if not isinstance(candidate, dict) or candidate.get('userId') != uid:
                    continue
                if run_id and candidate.get('runId') != run_id:
                    continue
                result = candidate
                break
            except Exception:
                continue
    if not result:
        return jsonify({'success': False, 'message': 'Pipeline result not available yet'}), 404
    return jsonify({'success': True, 'runId': result.get('runId'), 'result': result})


@app.route('/api/ai-agent/pipeline/stop', methods=['POST'])
def pipeline_stop():
    """Request the active pipeline to stop at the next step boundary."""
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    active_run = _pa_get_active_run(uid)
    if active_run and active_run.get('status') == 'running':
        _pa_update_active_run(uid, stopRequested=True, message='Stop requested by user')
        return jsonify({'success': True, 'message': 'Stop requested at next step boundary'})
    return jsonify({'success': False, 'message': 'No active pipeline to stop'}), 404


@app.route('/api/ai-agent/continue-scan', methods=['POST'])
def continue_scan_shared():
    """Shared Continue Scan endpoint — single source of truth for ALL pipeline paths.
    Called by: frontend Continue Scan button, Run Manual Pipeline, Test Scheduled Run, Scheduled Auto Run.
    Delegates to _pa_continue_scan_headless for identical rules.
    """
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    data = request.get_json(silent=True) or {}
    scanner_results = data.get('scannerResults') or data.get('results') or []
    risk_profile = data.get('riskProfile') or data.get('risk_profile') or 'medium'
    time_horizon = data.get('timeHorizon') or data.get('time_horizon') or 'mid'
    pipeline_mode = data.get('pipelineMode') or data.get('mode') or 'hybrid'
    trade_mode = data.get('tradeMode') or data.get('trade_mode') or 'paper'

    if not scanner_results:
        return jsonify({'success': True, 'results': [], 'summary': {'eligible': 0}, 'message': 'No scanner results provided'})

    try:
        candidates, stats = _pa_continue_scan_headless(
            scanner_results,
            risk_profile=risk_profile,
            time_horizon=time_horizon,
            pipeline_mode=pipeline_mode,
            trade_mode=trade_mode
        )
        return jsonify({
            'success': True,
            'results': candidates,
            'summary': stats,
            'contextUsed': {
                'riskProfile': risk_profile,
                'timeHorizon': time_horizon,
                'pipelineMode': pipeline_mode,
                'tradeMode': trade_mode,
            }
        })
    except Exception as e:
        _pa_log_error('[ContinueScanShared] error: %s' % e)
        return jsonify({'success': False, 'message': str(e)[:200]}), 500


@app.route('/api/ai-agent/fine-scan', methods=['POST'])
def fine_scan_shared():
    """Shared Fine Scan endpoint — single source of truth for ALL pipeline paths.
    Delegates to _pa_fine_scan_headless for regime detection, strategy matching,
    multi-strategy backtest, AI entry quality, advanced scan, and decision.
    """
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    data = request.get_json(silent=True) or {}
    candidates = data.get('candidates') or []
    risk_profile = data.get('riskProfile') or data.get('risk_profile') or 'medium'
    time_horizon = data.get('timeHorizon') or data.get('time_horizon') or 'mid'
    pipeline_mode = data.get('pipelineMode') or data.get('mode') or 'hybrid'
    trade_mode = data.get('tradeMode') or data.get('trade_mode') or 'paper'

    if not candidates:
        return jsonify({'success': True, 'results': [], 'summary': {'scanned': 0}, 'message': 'No candidates provided'})

    try:
        results = _pa_fine_scan_headless(uid, candidates,
                                          risk_profile=risk_profile, time_horizon=time_horizon,
                                          pipeline_mode=pipeline_mode, trade_mode=trade_mode)
        decisions = {'Continue': 0, 'Watch': 0, 'Reject': 0, 'NeedMoreData': 0, 'Skip': 0}
        _failed_count = 0
        _dq_blocked = 0
        _top_continue = []
        for r in results:
            d = r.get('decision', '')
            if d in decisions: decisions[d] += 1
            if r.get('scanStatus') == 'failed': _failed_count += 1
            if r.get('decisionSource') == 'data_quality_gate': _dq_blocked += 1
            if d == 'Continue': _top_continue.append(r.get('symbol'))
        _ai_stats = results[0].get('fineScanAiStats') if results and isinstance(results[0].get('fineScanAiStats'), dict) else {}
        return jsonify({
            'success': True,
            'results': results,
            'summary': {
                'scanned': len(results),
                'decisions': decisions,
                'failed': _failed_count,
                'data_quality_blocked': _dq_blocked,
                'top_continue': _top_continue[:10],
                'ai': {
                    'status': _ai_stats.get('status', 'disabled'),
                    'requested': _ai_stats.get('requestedSymbols', 0),
                    'reviewed': _ai_stats.get('reviewedSymbols', 0),
                    'challenged': _ai_stats.get('challengedSymbols', 0),
                    'provider': _ai_stats.get('provider'),
                    'model': _ai_stats.get('model'),
                    'retryAttempts': _ai_stats.get('retryAttempts', 0),
                },
            },
            'contextUsed': {'riskProfile': risk_profile, 'timeHorizon': time_horizon, 'pipelineMode': pipeline_mode, 'tradeMode': trade_mode},
        })
    except Exception as e:
        _pa_log_error('[FineScanShared] error: %s' % e)
        return jsonify({'success': False, 'message': str(e)[:200]}), 500


@app.route('/api/ai-agent/scanner-news/<symbol>', methods=['GET'])
def scanner_news_lazy(symbol):
    """Lazy-fetch Alpaca news for a single symbol when the user expands detail.
    Returns same topNews/newsSource/newsFetchReason shape as the scanner result.
    """
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    symbol = (symbol or '').strip().upper()
    if not symbol:
        return jsonify({'success': False, 'message': 'Symbol is required'}), 400

    market_cfg, cfg_status = resolve_alpaca_config_strict_user('market_data')
    if cfg_status != 'ok':
        return jsonify({
            'success': True,
            'symbol': symbol,
            'topNews': None,
            'newsCount': 0,
            'hasNews': False,
            'newsSource': 'Alpaca News not configured',
            'newsFetchReason': 'alpaca_news_not_configured' if cfg_status == 'config_required' else 'auth_required',
            'dataSources': {'news': 'Alpaca News not configured'},
            'provenance': {'news': 'Alpaca News not configured'},
        })

    try:
        news_by_symbol, errors, stats = _inst_fetch_alpaca_news(
            [symbol],
            market_cfg,
            days_back=7,
            batch_size=1,
            page_limit=3,
            max_retries=2,
        )
        err = errors.get(symbol)
        if err:
            _pa_log('[ScannerNews] Alpaca lazy fetch %s FAILED: %s' % (symbol, err))
            retry_after = 65 if 'rate_limited' in str(err) or '429' in str(err) else None
            return jsonify({
                'success': True,
                'symbol': symbol,
                'topNews': None,
                'newsCount': 0,
                'hasNews': False,
                'newsSource': 'Alpaca News error: %s' % str(err)[:80],
                'newsFetchReason': str(err)[:140],
                'retryAfterSeconds': retry_after,
                'newsFetchStats': stats,
                'dataSources': {'news': 'Alpaca /v1beta1/news'},
                'provenance': {'news': 'Alpaca /v1beta1/news'},
            })

        news_items = news_by_symbol.get(symbol, []) or []
        if news_items:
            top_sorted = sorted(news_items, key=lambda n: str(n.get('createdAt') or n.get('updatedAt') or ''), reverse=True)
            best = top_sorted[0]
            signal = _inst_news_signal(top_sorted)

            def _shape_news(item):
                return {
                    'id': item.get('id'),
                    'title': item.get('headline', ''),
                    'headline': item.get('headline', ''),
                    'source': item.get('source') or 'Alpaca News',
                    'publisher': item.get('source') or 'Alpaca News',
                    'published': item.get('createdAt') or item.get('updatedAt'),
                    'publishedAt': item.get('createdAt') or item.get('updatedAt'),
                    'url': item.get('url') or '',
                    'summary': (item.get('summary') or '')[:300],
                    'symbols': item.get('symbols') or [],
                }

            return jsonify({
                'success': True,
                'symbol': symbol,
                'topNews': _shape_news(best),
                'allNews': [_shape_news(n) for n in top_sorted[:5]],
                'newsCount': len(news_items),
                'hasNews': True,
                'newsSentiment': signal.get('sentiment'),
                'newsScore': signal.get('score'),
                'sentimentScore': signal.get('score'),
                'eventRisk': signal.get('eventRisk'),
                'eventTags': signal.get('tags'),
                'newsSource': 'Alpaca News',
                'newsFetchReason': 'fetched: %d articles in 7d (lazy)' % len(news_items),
                'newsFetchStats': stats,
                'dataSources': {'news': 'Alpaca /v1beta1/news'},
                'provenance': {'news': 'Alpaca /v1beta1/news'},
            })
        else:
            _pa_log('[ScannerNews] Alpaca lazy fetch %s: no news in 7d' % symbol)
            return jsonify({
                'success': True,
                'symbol': symbol,
                'topNews': None,
                'newsCount': 0,
                'hasNews': False,
                'newsSource': 'Alpaca News: no news in 7d',
                'newsFetchReason': 'no_news_last_7d',
                'newsFetchStats': stats,
                'dataSources': {'news': 'Alpaca /v1beta1/news'},
                'provenance': {'news': 'Alpaca /v1beta1/news'},
            })
    except Exception as e:
        _pa_log('[ScannerNews] Alpaca lazy fetch %s exception: %s' % (symbol, e))
        return jsonify({
            'success': True,
            'symbol': symbol,
            'topNews': None,
            'newsCount': 0,
            'hasNews': False,
            'newsSource': 'Alpaca News error: %s' % str(e)[:80],
            'newsFetchReason': 'alpaca_news_exception: %s' % str(e)[:100],
            'dataSources': {'news': 'Alpaca /v1beta1/news'},
            'provenance': {'news': 'Alpaca /v1beta1/news'},
        })


@app.route('/api/ai-agent/pipeline-auto/run-headless-test', methods=['POST'])
def pipeline_auto_run_headless_test():
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    data = request.get_json(silent=True) or {}
    dry_run = bool(data.get('dryRun', True))
    interval = int(data.get('intervalMinutes') or 15)
    mode = data.get('mode') or (_pa_get_config(uid).get('mode', 'ai') if _pa_get_config(uid) else 'ai')
    if not dry_run and mode != 'ai':
        dry_run = True
    if not _pa_try_reserve_user_run(uid, 'headless_test'):
        if not _pa_user_run_is_reserved(uid):
            return _pa_pipeline_capacity_response()
        return jsonify({'success': False, 'message': 'Headless pipeline is already running', 'status': 'already_running'}), 409
    try:
        summary = _pa_run_pipeline(uid, interval, mode, trigger='headless_test', dry_run=dry_run)
        _pa_add_run_history(uid, {
            'trigger_type': 'headless_test',
            'status': 'success' if summary.get('errors', 0) == 0 else 'failed',
            'reason': 'headless dry-run test completed' if dry_run else 'headless test completed',
            'source': 'backend_test_endpoint',
            'market_open': None,
            'market_status': 'test',
            'market_status_source': 'manual_test',
            'started_at': summary.get('startedAt'),
            'finished_at': summary.get('finishedAt'),
            'duration_seconds': summary.get('durationSeconds', 0),
            'interval_minutes': interval,
            'mode': mode,
            'summary': summary,
            'error': summary.get('lastError'),
        })
        return jsonify({'success': summary.get('errors', 0) == 0, 'dryRun': dry_run, 'mode': mode, 'summary': summary})
    finally:
        _pa_release_user_run(uid)


@app.route('/api/ai-agent/pipeline-auto/run-now', methods=['POST'])
def pipeline_auto_run_now():
    """Run one background auto pipeline immediately without enabling scheduler.

    Trigger = auto_run_now. Source = Auto Background.
    Does NOT modify enabled, intervalMinutes, or next_run_at.
    Caller: frontend "Run Auto Pipeline Now" button.
    """
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    trigger = 'auto_run_now'

    config = _pa_get_config(uid) or {}
    if _pa_is_circuit_breaker_open(config):
        return jsonify({
            'success': False,
            'status': 'circuit_open',
            'reason': 'circuit_breaker_open',
            'message': 'Automated research is paused by the circuit breaker. Position protection remains active.',
            'retryAt': config.get('circuit_breaker_until', ''),
        }), 409

    if not _pa_try_reserve_user_run(uid, 'auto_run_now'):
        if not _pa_user_run_is_reserved(uid):
            return _pa_pipeline_capacity_response()
        active_run = _pa_get_active_run(uid)
        is_auto = active_run and active_run.get('trigger', '') in ('market_auto_run', 'headless_market_auto_run', 'toggle_on', 'auto_run_now')
        if is_auto:
            return jsonify({'success': False, 'error': 'auto_run_already_running',
                            'message': 'An auto pipeline is already running.'}), 409
        else:
            return jsonify({'success': False, 'error': 'manual_pipeline_running',
                            'message': 'Manual pipeline is running. Please wait for it to complete.'}), 409

    _ctx = _pa_resolve_auto_run_context(uid, config)
    mode = _ctx['mode']
    interval = _ctx['interval']
    risk_profile = _ctx['risk_profile']
    time_horizon = _ctx['time_horizon']
    trade_mode = _ctx['trade_mode']

    run_id = 'auto-now-%d' % int(time.time())
    _pa_log('[AutoRunNow] endpoint user=%s mode=%s risk=%s horizon=%s trade=%s context=%s runId=%s' % (
        uid[:8], mode, risk_profile, time_horizon, trade_mode, _ctx['contextSource'], run_id))

    def _background_auto_now():
        try:
            cfg_copy = _pa_get_config(uid) or {}
            # Do NOT change enabled or intervalMinutes
            summary = _pa_execute_and_save(uid, cfg_copy, interval, mode, trigger=trigger,
                                            risk_profile=risk_profile, time_horizon=time_horizon,
                                            trade_mode=trade_mode, run_id=run_id)
            _pa_add_run_history(uid, {
                'trigger_type': trigger,
                'status': 'success' if (summary and summary.get('errors', 0) == 0) else 'failed',
                'reason': 'Manual test of scheduled auto run (user clicked Run Auto Pipeline Now).',
                'source': 'Market Auto Run',
                'market_open': None,
                'market_status': 'manual_trigger',
                'market_status_source': 'auto_run_now_button',
                'started_at': summary.get('startedAt') if summary else None,
                'finished_at': summary.get('finishedAt') if summary else None,
                'duration_seconds': summary.get('durationSeconds', 0) if summary else 0,
                'interval_minutes': interval,
                'mode': mode,
                'summary': summary,
                'error': summary.get('lastError') if summary else 'No summary returned',
                'run_id': run_id,
            })
            _pa_log('[ManualPipeline] auto-run-now completed user=%s runId=%s errors=%d' % (
                uid[:8], run_id, summary.get('errors', 0) if summary else -1))
        except Exception:
            import traceback
            _pa_log_error('[ManualPipeline] auto-run-now failed: %s' % traceback.format_exc())

    threading.Thread(target=_background_auto_now, daemon=True).start()
    order_authority = _pa_order_authority(config, mode=mode, trade_mode=trade_mode)
    return jsonify({
        'success': True,
        'runId': run_id,
        'status': 'running',
        'message': 'Auto pipeline started in background.',
        'orderAuthority': order_authority,
    })


@app.route('/api/ai-agent/pipeline-auto/config', methods=['POST'])
def pipeline_auto_config():
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    data = request.get_json(silent=True) or {}
    existing_config = _pa_get_config(uid) or {}
    enabled_raw = data.get('enabled', False)
    enabled = enabled_raw is True or (isinstance(enabled_raw, str) and enabled_raw.lower() == 'true')
    interval_minutes = data.get('intervalMinutes', None)
    mode = data.get('mode', 'hybrid')
    last_run_at = data.get('lastRunAt', None)
    if enabled:
        try:
            interval_minutes = int(interval_minutes)
        except (TypeError, ValueError):
            interval_minutes = 0
        if interval_minutes not in (15, 30, 60, 120):
            return jsonify({'success': False, 'reason': 'invalid_interval', 'message': 'Schedule interval must be 15, 30, 60, or 120 minutes.'}), 400
    if mode not in ('manual', 'hybrid', 'ai'):
        return jsonify({'success': False, 'reason': 'invalid_mode', 'message': 'Pipeline mode is invalid.'}), 400

    config = existing_config
    was_enabled = config.get('enabled', False)
    config['enabled'] = enabled
    config['interval_minutes'] = interval_minutes
    config['mode'] = mode
    # Persist user context so scheduled runs use the same risk/horizon/trade as the UI
    config['risk_profile'] = data.get('riskProfile') or data.get('risk_profile') or config.get('risk_profile') or 'medium'
    config['time_horizon'] = data.get('timeHorizon') or data.get('time_horizon') or config.get('time_horizon') or 'mid'
    config['trade_mode'] = data.get('tradeMode') or data.get('trade_mode') or config.get('trade_mode') or 'paper'
    if data.get('leverageEnabled') is not None:
        config['leverage_enabled'] = data.get('leverageEnabled') is True
    requested_live_auto = data.get('liveAutoTradingEnabled') if data.get('liveAutoTradingEnabled') is not None else config.get('live_auto_trading_enabled', False)
    requested_live_auto = requested_live_auto is True or (
        isinstance(requested_live_auto, str) and requested_live_auto.lower() == 'true'
    )
    # Authority is durable across mode/account changes. It is active only in
    # Real + Full AI, and can be revoked only by the dedicated authority control.
    if requested_live_auto and mode == 'ai' and config.get('trade_mode') == 'real':
        authority_error = _pa_validate_live_auto_authority(uid, config)
        if authority_error:
            return jsonify({'success': False, **authority_error}), 400
    config['live_auto_trading_enabled'] = requested_live_auto
    if requested_live_auto:
        config['live_auto_authorized_method'] = 'explicit_confirmation'
        config.pop('live_auto_authorized_aal', None)
        config['live_auto_authorized_at'] = datetime.now(timezone.utc).isoformat()
        config['live_auto_authorized_by'] = uid
    config['updated_at'] = datetime.now(timezone.utc).isoformat()
    if not enabled:
        config['next_run_at'] = ''
        config['stopRequested'] = True
        config['disabled_at'] = datetime.utcnow().isoformat()
        config['last_decision'] = 'disabled'
        active_run = _pa_get_active_run(uid)
        if active_run and active_run.get('status') == 'running':
            _pa_update_active_run(
                uid,
                stopRequested=True,
                message='Stop requested because automation was disabled',
            )
    else:
        config['stopRequested'] = False

    # If frontend reports a completed run, update last_run_at so backend scheduler
    # calculates the next interval from this timestamp rather than triggering again
    if last_run_at:
        config['last_run_at'] = last_run_at
        config['last_decision'] = 'pipeline_success'
        config['last_run_source'] = 'frontend_auto'
        next_time = dateutil.parser.isoparse(last_run_at) + timedelta(minutes=interval_minutes)
        config['next_run_at'] = next_time.isoformat()
        # Legacy compatibility: accept old frontend completion sync if it appears.
        _pa_add_run_history(uid, {
            'trigger_type': 'auto_market_session',
            'status': 'success',
            'reason': 'pipeline completed (legacy frontend sync)',
            'source': 'frontend_auto',
            'market_open': True,
            'market_status': 'open',
            'market_status_source': 'frontend_sync',
            'started_at': last_run_at,
            'finished_at': last_run_at,
            'duration_seconds': 0,
            'interval_minutes': interval_minutes or 0,
            'mode': mode,
        })

    # Only a newly enabled or incomplete schedule is due immediately. Routine
    # context sync must not reset an existing schedule to "now".
    if enabled and not last_run_at and (not was_enabled or not config.get('next_run_at')):
        config['next_run_at'] = 'now'
        config['last_decision'] = 'enabled'

    success, reason = _pa_save_config(uid, config)
    _pa_ensure_scheduler()
    if enabled and not was_enabled and success:
        _pa_log('config enabled user=%s interval=%dm trigger_immediate=true' % (uid[:8], interval_minutes or 0))
        if _pa_is_circuit_breaker_open(config):
            config['last_decision'] = 'circuit_breaker_open'
            config['next_run_at'] = config.get('circuit_breaker_until', '')
            _pa_save_config(uid, config)
            _pa_log('config armed user=%s immediate_run=false reason=circuit_breaker' % uid[:8])
            return jsonify({
                'success': True,
                'enabled': True,
                'status': 'circuit_open',
                'reason': 'circuit_breaker_open',
                'message': 'Configuration saved. Automated research will resume after the circuit breaker closes; position protection remains active.',
                'retryAt': config.get('circuit_breaker_until', ''),
            })
        if interval_minutes:
            _immed_trade_mode = config.get('trade_mode') or config.get('tradeMode') or 'paper'
            _immed_is_open, _immed_mkt_status, _immed_mkt_source, _, _, _immed_stage = _pa_check_market_open(uid, _immed_trade_mode)
            _pa_log('[PipelineAutoConfig] toggle requested enabled=true marketStage=%s' % (_immed_stage or 'closed'))
            if _immed_is_open:
                # Execute headless immediately — no claim window, no frontend involvement
                _pa_log('[PipelineAutoConfig] toggle-on immediate headless run start')
                _toggle_ctx = _pa_resolve_auto_run_context(uid, config)
                def _toggle_run(_uid, _cfg, _interval, _mode, _risk, _horizon, _trade):
                    try:
                        cfg_copy = _pa_get_config(_uid) or {}
                        _pa_execute_and_save(_uid, cfg_copy, _interval, _mode, trigger='toggle_on',
                                              risk_profile=_risk, time_horizon=_horizon, trade_mode=_trade)
                    except Exception:
                        import traceback
                        _pa_log_error('[ToggleOn] headless run error: %s' % traceback.format_exc())
                if _pa_try_reserve_user_run(uid, 'toggle_on'):
                    threading.Thread(target=_toggle_run, args=(
                        uid, dict(config), _toggle_ctx['interval'], _toggle_ctx['mode'],
                        _toggle_ctx['risk_profile'], _toggle_ctx['time_horizon'], _toggle_ctx['trade_mode']
                    ), daemon=True).start()
                    return jsonify({
                        'success': True,
                        'message': 'Configuration saved, pipeline started',
                        'enabled': True,
                        'orderAuthority': _pa_order_authority(config),
                    })
                _pa_log('[PipelineAutoConfig] toggle-on immediate run skipped reason=already_running')
    elif not enabled and was_enabled:
        _pa_log('config disabled user=%s saved enabled=false stopRequested=true' % uid[:8])
    elif enabled:
        _pa_log('config updated user=%s interval=%dm' % (uid[:8], interval_minutes or 0))
    if last_run_at:
        return jsonify({
            'success': success,
            'message': 'Configuration saved' if success else 'Failed to save configuration',
            'reason': reason,
            'lastRunAtSynced': True,
            'orderAuthority': _pa_order_authority(config),
        })
    return jsonify({
        'success': success,
        'message': 'Configuration saved' if success else 'Failed to save configuration',
        'reason': reason,
        'orderAuthority': _pa_order_authority(config),
    })


@app.route('/api/ai-agent/pipeline-auto/history', methods=['GET'])
def pipeline_auto_history():
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    try:
        limit = max(1, min(100, int(request.args.get('limit', 5))))
    except (ValueError, TypeError):
        limit = 5
    history = _pa_get_history(uid, limit)
    return jsonify({'success': True, 'history': history, 'count': len(history)})


def _pipeline_auto_get_market_schedule(uid=None, days=15):
    """Return market open/close schedule for next `days` days.
    Always returns a days array. Uses Alpaca calendar API with fallback.
    Returns: (days_list, source_string, warning_string)
    """
    now_et = _pa_now_et()
    start_date = now_et.replace(hour=0, minute=0, second=0, microsecond=0)
    end_date = start_date + timedelta(days=days - 1)
    source = 'alpaca_calendar'
    warning = ''
    alpaca_calendar = []

    # Try Alpaca calendar API
    try:
        auto_config = _pa_get_config(uid) if uid else {}
        calendar_mode = (auto_config or {}).get('trade_mode') or 'paper'
        alpaca_config = resolve_alpaca_config_for_user(uid, calendar_mode) if uid else {}
        alpaca_key = alpaca_config.get('api_key', '')
        alpaca_secret = alpaca_config.get('api_secret', '')
        if alpaca_key and alpaca_secret:
            alpaca_base = alpaca_config.get('base_url') or (
                'https://paper-api.alpaca.markets' if calendar_mode == 'paper' else 'https://api.alpaca.markets'
            )
            headers = {'Apca-Api-Key-Id': alpaca_key, 'Apca-Api-Secret-Key': alpaca_secret}
            url = '%s/v2/calendar?start=%s&end=%s' % (
                alpaca_base,
                start_date.strftime('%Y-%m-%d'),
                end_date.strftime('%Y-%m-%d')
            )
            resp = requests.get(url, headers=headers, timeout=10)
            if resp.status_code == 200:
                alpaca_calendar = resp.json()
                if isinstance(alpaca_calendar, list):
                    _pa_log('Market schedule: Alpaca calendar returned %d days' % len(alpaca_calendar))
                else:
                    alpaca_calendar = []
                    source = 'fallback_basic_hours'
            else:
                _pa_log_error('Alpaca calendar API returned %d' % resp.status_code)
                source = 'fallback_basic_hours'
        else:
            source = 'fallback_basic_hours'
    except Exception as e:
        _pa_log_error('Alpaca calendar API failed: %s' % e)
        source = 'fallback_basic_hours'

    # Build a lookup from Alpaca calendar
    alpaca_lookup = {}
    if source == 'alpaca_calendar' and alpaca_calendar:
        for entry in alpaca_calendar:
            date_str = entry.get('date', '')
            if date_str:
                alpaca_lookup[date_str] = entry

    if source != 'alpaca_calendar':
        warning = 'Alpaca calendar unavailable; using weekday/time fallback'

    weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']
    result_days = []
    today_str = start_date.strftime('%Y-%m-%d')

    for i in range(days):
        day = start_date + timedelta(days=i)
        date_str = day.strftime('%Y-%m-%d')
        weekday_num = day.weekday()
        weekday_name = weekdays[weekday_num]

        is_open = False
        status = 'closed'
        reason = ''
        open_time = None
        close_time = None
        day_source = source
        is_early_close = False

        # Check Alpaca calendar
        cal_entry = alpaca_lookup.get(date_str)
        if cal_entry:
            cal_open = cal_entry.get('open', '')
            cal_close = cal_entry.get('close', '')
            if cal_open and cal_close:
                is_open = True
                status = 'open'
                open_time = cal_open[:5] if len(cal_open) >= 5 else cal_open
                close_time = cal_close[:5] if len(cal_close) >= 5 else cal_close
                reason = 'Regular trading session'
                try:
                    close_hour = int(cal_close[:2])
                    if close_hour < 15 or (close_hour == 15 and int(cal_close[3:5]) < 30):
                        is_early_close = True
                        status = 'early_close'
                        reason = 'Early close'
                except (ValueError, IndexError):
                    pass
            else:
                is_open = False
                status = 'holiday'
                reason = 'Holiday (Alpaca calendar)'
                day_source = 'alpaca_calendar'
        else:
            # Not in Alpaca calendar — fallback checks.
            # In fallback mode, NEVER show Holiday. Only weekend/open.
            if weekday_num >= 5:
                is_open = False
                status = 'weekend'
                reason = 'Weekend'
            elif source == 'fallback_basic_hours':
                # Fallback: check enhanced holiday calendar before marking as Open
                holiday_name = _pa_is_holiday(day)
                if holiday_name:
                    is_open = False
                    status = 'holiday'
                    reason = '%s (fallback holiday calendar)' % holiday_name
                    day_source = 'fallback_holiday_calendar'
                elif weekday_num >= 5:
                    is_open = False
                    status = 'weekend'
                    reason = 'Weekend'
                else:
                    is_open = True
                    status = 'open'
                    reason = 'Regular trading session (unverified fallback)'
                    open_time = '09:30'
                    close_time = '16:00'
                    day_source = 'fallback_basic_hours'
            else:
                # Alpaca calendar source but no entry for this date — could be holiday
                holiday_name = _pa_is_holiday(day)
                if holiday_name:
                    is_open = False
                    status = 'holiday'
                    reason = holiday_name
                elif weekday_num >= 5:
                    is_open = False
                    status = 'weekend'
                    reason = 'Weekend'
                else:
                    is_open = True
                    status = 'open'
                    reason = 'Regular trading session'
                    open_time = '09:30'
                    close_time = '16:00'

        result_days.append({
            'date': date_str, 'weekday': weekday_name, 'marketOpen': is_open,
            'status': status, 'reason': reason, 'openTime': open_time,
            'closeTime': close_time, 'autoRun': False, 'source': day_source,
            'earlyClose': is_early_close,
        })

    # Set autoRun based on whether auto-run is enabled and market is open
    if uid:
        config = _pa_get_config(uid)
        auto_enabled = config.get('enabled', False) if config else False
        for d in result_days:
            d['autoRun'] = auto_enabled and d['marketOpen']

    return result_days, source, warning


@app.route('/api/ai-agent/pipeline-auto/market-schedule', methods=['GET'])
def pipeline_auto_market_schedule():
    user = require_auth()
    if not user:
        return jsonify({'success': False, 'message': 'Authentication required'}), 401
    uid = user['id']
    try:
        days = max(1, min(90, int(request.args.get('days', 15))))
    except (ValueError, TypeError):
        days = 15
    try:
        schedule, source, warning = _pipeline_auto_get_market_schedule(uid, days)
    except Exception as e:
        _pa_log_error('Market schedule error: %s' % e)
        schedule, source, warning = [], 'fallback_basic_hours', 'Error generating schedule: %s' % str(e)
    result = {
        'success': True,
        'timezone': 'America/New_York',
        'source': source,
        'days': schedule,
    }
    if warning:
        result['warning'] = warning
    return jsonify(result)


# ── Scheduler startup ──
def _pa_ensure_scheduler():
    global _PA_SCHEDULER_STARTED, _PA_SCHEDULER_THREAD
    with _PA_LOCK:
        if _PA_SCHEDULER_STARTED and _PA_SCHEDULER_THREAD and _PA_SCHEDULER_THREAD.is_alive():
            return
        _PA_SCHEDULER_STARTED = True
        _PA_SCHEDULER_THREAD = threading.Thread(target=_pa_scheduler_loop, daemon=True, name='pipeline-auto-scheduler')
        _PA_SCHEDULER_THREAD.start()
        _pa_log('pipeline-auto scheduler started')


# Crypto is deliberately registered as an isolated 24/7 subsystem.  It reuses
# the authenticated per-user credential resolver and operation store, but does
# not inherit the equity market clock or equity order assumptions above.
def _crypto_ai_risk_review(uid, evidence):
    """Run the user's configured model as a bounded crypto risk challenger.

    The crypto service validates the model output again and is the sole owner
    of target weights and broker fields.  Missing or malformed model output is
    returned as an explicit unavailable review rather than being mistaken for
    an approval.
    """
    ai_config, source = resolve_ai_config_for_user(uid)
    if not ai_config.get('apiKey'):
        return {
            'status': 'not_configured',
            'verdict': 'unavailable',
            'action': evidence.get('action'),
            'summary': 'No user AI provider is configured.',
            'source': source,
        }

    allowed = [str(value).upper() for value in (evidence.get('allowedActions') or [])]
    system_prompt = (
        'You are AlphaLab Crypto Risk Reviewer, a second-line reviewer for a '
        'spot-only BTC/USD and ETH/USD system. The deterministic strategy and '
        'hard risk gates have final authority. You may only preserve or reduce '
        'risk: never originate a position, increase target weight, add an '
        'asset, remove a stop, bypass stale-data/account/kill-switch controls, '
        'or delay a mandatory EXIT. Return one JSON object only with keys '
        'verdict (clear, caution, reject), action, summary, counterEvidence, '
        'and invalidation. Keep summary under 240 characters.'
    )
    review_payload = {
        'contract': {
            'deterministicAction': evidence.get('action'),
            'allowedActions': allowed,
            'maximumTargetWeight': evidence.get('targetWeight'),
            'rule': 'Preserve or reduce risk only.',
        },
        'evidence': evidence,
    }
    parsed, error = _inst_call_ai_trader(
        ai_config,
        system_prompt,
        json.dumps(review_payload, separators=(',', ':'), default=str),
    )
    if error or not isinstance(parsed, dict):
        return {
            'status': 'unavailable',
            'verdict': 'unavailable',
            'action': evidence.get('action'),
            'summary': str(error or 'AI review was not parseable')[:240],
            'source': source,
        }
    return {
        'status': 'reviewed',
        'verdict': str(parsed.get('verdict') or 'caution').strip().lower(),
        'action': str(parsed.get('action') or evidence.get('action') or 'HOLD').strip().upper(),
        'summary': str(parsed.get('summary') or '')[:240],
        'counterEvidence': str(parsed.get('counterEvidence') or '')[:400],
        'invalidation': str(parsed.get('invalidation') or '')[:400],
        'source': source,
    }


def _crypto_ai_status(uid):
    """Expose only non-secret Settings AI metadata to the crypto workspace."""
    ai_config, source = resolve_ai_config_for_user(uid)
    return {
        'configured': bool(ai_config.get('apiKey')),
        'status': ai_config.get('testStatus') or ('configured' if ai_config.get('apiKey') else 'not_configured'),
        'provider': ai_config.get('provider') or '',
        'model': ai_config.get('model') or '',
        'source': source,
    }


def _crypto_discord_notify(uid, event_type, payload):
    """Adapt crypto events to the existing localized notification contract."""
    body = dict(payload or {})
    body['assetClass'] = 'crypto'
    if event_type == 'recommendation' and not body.get('recommendations'):
        body['recommendations'] = [{
            'symbol': body.get('symbol'),
            'action': body.get('action'),
            'reason': body.get('reason'),
            'targetWeight': body.get('targetWeight'),
            'confidence': body.get('confidence'),
        }]
        body.setdefault('fingerprint', '%s:%s:%s:%s' % (
            body.get('symbol') or '-', body.get('action') or '-',
            body.get('targetWeight') or '-', body.get('regime') or '-',
        ))
    if event_type == 'order':
        action = str(body.get('action') or '').upper()
        body.setdefault('side', 'BUY' if action in ('BUY', 'ADD') else 'SELL')
        body.setdefault('event_id', body.get('orderId'))
    if event_type == 'risk_alert':
        body.setdefault('reason', body.get('error') or body.get('event'))
        body.setdefault('step', 'Crypto automation')
        body.setdefault('status', 'blocked')
    return send_discord_notification(uid, event_type, body)


